    (4, '(Dialogo) A: "Buongiorno, Dottor Rossi." / B: "Buongiorno a Lei. Come sta?"', 'phrase', 'c0c112eb40e93086a49ad51f002cd194c0d279cc250fc252c4be693fc44583b3', 'A1', true, 'easy', 'firebase', 1, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "frase_001", "note_culturale": ""}', NULL),
    (5, '(Dialogo) A: "Hyvää huomenta, tohtori Rossi." / B: "Hyvää huomenta. Kuinka voitte?"', 'phrase', '96f32de8b7c18b4bb536feac1fcdcaaa704fe0e0ecf706794b7072878896cca8', 'A1', true, 'easy', 'firebase', 2, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "frase_001", "note_culturale": ""}', NULL),
    (6, '(Dialogo) A: "Good morning, Dr. Rossi." / B: "Good morning. How are you?"', 'phrase', '2237b019b02fbb99c7d01bdfb0dbbacdf427295d3f442e33178bc2b607059eca', 'A1', true, 'easy', 'firebase', 3, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "frase_001", "note_culturale": ""}', NULL),
    (7, '(Dialogo) A: "Devo andare, ci vediamo domani." / B: "Perfetto, a domani!"', 'phrase', 'e6103c4931582cfa5371d5afcfb8408448d7cfcf17f7ffc623176861fe546dcd', 'A1', true, 'easy', 'firebase', 1, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "frase_002", "note_culturale": ""}', NULL),
    (8, '(Dialogo) A: "Minun täytyy mennä, nähdään huomenna." / B: "Selvä, huomiseen!"', 'phrase', '8b2028d8d29c86c2f6d1136af3e80eecf8f90746d800a1a3be10baac0679a143', 'A1', true, 'easy', 'firebase', 2, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "frase_002", "note_culturale": ""}', NULL),
    (9, '(Dialogo) A: "I have to go, see you tomorrow." / B: "Sounds good, see you tomorrow!"', 'phrase', '571a366e05817430c70da404123d6614eecc280b7efb96cc7d72c2ecb7be968c', 'A1', true, 'easy', 'firebase', 3, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "frase_002", "note_culturale": ""}', NULL),
    (10, '(Dialogo) A: "È stato un piacere, buona serata!" / B: "Altrettanto!"', 'phrase', '2a964fadf7e0ddf3acb3e6c50328343291aae4b46ea27a68c105bce2fa8e7afc', 'A1', true, 'easy', 'firebase', 1, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "frase_003", "note_culturale": ""}', NULL),
    (11, '(Dialogo) A: "Oli hauska tavata, hyvää illanjatkoa!" / B: "Samoin!"', 'phrase', '0ae90d5ba0f753c5504d5e545c53ede657151966c1819f7f535ba5e93cedb529', 'A1', true, 'easy', 'firebase', 2, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "frase_003", "note_culturale": ""}', NULL),
    (12, '(Dialogo) A: "It was a pleasure, have a good evening!" / B: "You too!"', 'phrase', 'c21803ef92084aed75fc633ceaeae415c0d5b5bd47fd4fed247478031f482694', 'A1', true, 'easy', 'firebase', 3, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "frase_003", "note_culturale": ""}', NULL),
    (13, '(Dialogo) A: "Ciao Anna, tutto a posto?" / B: "Sì, tutto bene, grazie!"', 'phrase', 'ca097072f637bae7d530b66af30b3e8caab9300d0935562d1e879956d217287e', 'A1', true, 'easy', 'firebase', 1, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "frase_004", "note_culturale": ""}', NULL),
    (14, '(Dialogo) A: "Moi Anna, kaikki ok?" / B: "Joo, kaikki hyvin, kiitos!"', 'phrase', 'd4c9c2790f9747187d3ced19168e8c1f9908a97afcbf0e9dd2ac6c1780d56a6b', 'A1', true, 'easy', 'firebase', 2, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "frase_004", "note_culturale": ""}', NULL),
    (15, '(Dialogo) A: "Hi Anna, everything alright?" / B: "Yep, all good, thanks!"', 'phrase', '9caeab1779f3a7b70d8a783bbba0dd5aa0e8b7ebb0392216124c725ca8a172da', 'A1', true, 'easy', 'firebase', 3, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "frase_004", "note_culturale": ""}', NULL),
    (16, '(Dialogo) A: "Vado a casa, ciao!" / B: "Ciao, buona serata!"', 'phrase', 'f717e2fa374e4f82b123a9b36b7ee19316be2a83b173eeefc73ff187105d723b', 'A1', true, 'easy', 'firebase', 1, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "frase_005", "note_culturale": ""}', NULL),
    (17, '(Dialogo) A: "Menen kotiin, moi!" / B: "Moi moi, hyvää iltaa!"', 'phrase', 'dd27b366de5c285ec46c61b24c68f941e2a9df6e0545c2b84b2d6fb640f17d59', 'A1', true, 'easy', 'firebase', 2, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "frase_005", "note_culturale": ""}', NULL),
    (18, '(Dialogo) A: "I''m heading home, bye!" / B: "Bye, have a good evening!"', 'phrase', 'fb92055ac00203bb4d34ec5c05f36fa944eceacb2b9cd916c27978c5eed4ee53', 'A1', true, 'easy', 'firebase', 3, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "frase_005", "note_culturale": ""}', NULL),
    (19, '(Dialogo) A: "Ci vediamo più tardi al bar." / B: "Ok, a dopo!"', 'phrase', 'afc6f46325a86a4c4bd0370dfb52a1849ed57dd87614c1836d91513e2440de52', 'A1', true, 'easy', 'firebase', 1, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "frase_006", "note_culturale": ""}', NULL),
    (20, '(Dialogo) A: "Nähdään myöhemmin baarissa." / B: "Ok, nähdään!"', 'phrase', '0e791dc0fa7b573718f38224d1786e3d9b8fa3913b747723eb8f460601d951af', 'A1', true, 'easy', 'firebase', 2, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "frase_006", "note_culturale": ""}', NULL),
    (21, '(Dialogo) A: "See you later at the bar." / B: "Okay, see you later!"', 'phrase', '2ed036a7f5bfc50c3c5216316810671a9d60c4258c9f4c91935f9d1e52e7e755', 'A1', true, 'easy', 'firebase', 3, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "frase_006", "note_culturale": ""}', NULL),
    (22, '(Dialogo) A: "Vado a letto, buonanotte!" / B: "Notte! Sogni d''oro."', 'phrase', '3c7a09044beffb3417a58343c21c0b6e1ce71045fdbf9184ef7d813f068124c2', 'A1', true, 'easy', 'firebase', 1, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "frase_007", "note_culturale": ""}', NULL),
    (23, '(Dialogo) A: "Menen nukkumaan, hyvää yötä!" / B: "Öitä! Kauniita unia."', 'phrase', '71006fceaaf549d41a827ce8fb32a0a5c6474629943ed6a97d0e6091a6db241f', 'A1', true, 'easy', 'firebase', 2, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "frase_007", "note_culturale": ""}', NULL),
    (24, '(Dialogo) A: "I''m going to bed, goodnight!" / B: "Night! Sweet dreams."', 'phrase', '0ba315a69f59b2fd2c137868e98201a6b266714faafd0cd44bc3a1f2131cbc8b', 'A1', true, 'easy', 'firebase', 3, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "frase_007", "note_culturale": ""}', NULL),
    (25, '(Dialogo) A: "Ciao Marco! Da quanto tempo!" / B: "Eh già! Come stai?"', 'phrase', 'cb01310311aeab12b51b5c2424edd97e2a0573b38348daf0099ad7904e0fe6d7', 'A1', true, 'easy', 'firebase', 1, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "frase_008", "note_culturale": ""}', NULL),
    (26, '(Dialogo) A: "Moi Marco! Pitkästä aikaa!" / B: "Niinpä! Mitä kuuluu?"', 'phrase', '37de80e8e4b9108a88901b0a981b1fc7899ed83130024908cc8785abe81d835d', 'A1', true, 'easy', 'firebase', 2, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "frase_008", "note_culturale": ""}', NULL),
    (27, '(Dialogo) A: "Hi Marco! Long time no see!" / B: "I know! How are you?"', 'phrase', '529378f23bc8eb5a13ee198fe0f6825ec51f27631fd6de412e58053a03da5b83', 'A1', true, 'easy', 'firebase', 3, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "frase_008", "note_culturale": ""}', NULL),
    (28, '(Dialogo) A: "Scusate, devo scappare." / B: "Ok, ci sentiamo!"', 'phrase', 'a0b05b8f71b72e457ad040c73b99b3426038e44ddfec113c9d6c88888e01879a', 'A1', true, 'easy', 'firebase', 1, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "frase_009", "note_culturale": ""}', NULL),
    (29, '(Dialogo) A: "Anteeksi, minun on pakko juosta." / B: "Ok, soitellaan!"', 'phrase', '61c872b2c608dbee04781c78339691b53f526ac237f242cc967a4a738534f836', 'A1', true, 'easy', 'firebase', 2, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "frase_009", "note_culturale": ""}', NULL),
    (30, '(Dialogo) A: "Sorry, I''ve got to run." / B: "Okay, talk soon!"', 'phrase', '0d0d27fdfdfe67d3a2f1657a6213262941cb85dd08c0ff8083b723d9d1c6068e', 'A1', true, 'easy', 'firebase', 3, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "frase_009", "note_culturale": ""}', NULL),
    (31, '(Dialogo) A: "Buon weekend!" / B: "Grazie, anche a te!"', 'phrase', '1c03882b717fc4f73b15f54be7886c9fa514cc37d796834cc3fac91f493cae1b', 'A1', true, 'easy', 'firebase', 1, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "frase_010", "note_culturale": ""}', NULL),
    (32, '(Dialogo) A: "Hyvää viikonloppua!" / B: "Kiitos, samoin!"', 'phrase', '9df861fffbdc127eeca3083d3c6cfb8c2990d86bf14a6b64e7587350b971ee27', 'A1', true, 'easy', 'firebase', 2, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "frase_010", "note_culturale": ""}', NULL),
    (33, '(Dialogo) A: "Have a good weekend!" / B: "Thanks, you too!"', 'phrase', 'f53261828954fc8b6bb459dabd46940dc24579ff50311aa3bd318fae94e25370', 'A1', true, 'easy', 'firebase', 3, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "frase_010", "note_culturale": ""}', NULL),
    (34, '(Dialogo) A: "Piacere, sono Marco." / B: "Piacere mio, io sono Anna."', 'phrase', '923119b50e65cdc5e42e448c8d56f87d8f15c32920e129873110eeebf9a1c2f4', 'A1', true, 'easy', 'firebase', 1, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "frase_011", "note_culturale": ""}', NULL),
