    (36, '(Dialogo) A: "Nice to meet you, I''m Marco." / B: "Nice to meet you too, I''m Anna."', 'phrase', '2f92117293de26d4f34c58062ed8b71b28021486e1a405764b0dfd5b502be7f1', 'A1', true, 'easy', 'firebase', 3, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "frase_011", "note_culturale": ""}', NULL),
    (37, '(Dialogo) A: "Lui è Paolo, un mio amico." / B: "Ciao Paolo, piacere."', 'phrase', 'd6e01e22cfba02c56a8411bf3a1ab9c26e372acd20ef48f2e6385c2db9efad24', 'A1', true, 'easy', 'firebase', 1, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "frase_012", "note_culturale": ""}', NULL),
    (38, '(Dialogo) A: "Tämä on Paolo, ystäväni." / B: "Hei Paolo, hauska tutustua."', 'phrase', '3092f62b076b7e9f998fcb485e4992e0d15b546ed38fd028280782b190f749d3', 'A1', true, 'easy', 'firebase', 2, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "frase_012", "note_culturale": ""}', NULL),
    (39, '(Dialogo) A: "This is Paolo, a friend of mine." / B: "Hi Paolo, nice to meet you."', 'phrase', '979387ab4ab4351e273115a4709aee27a8daa4368b5737e11b7e9f53713b013f', 'A1', true, 'easy', 'firebase', 3, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "frase_012", "note_culturale": ""}', NULL),
