    (48, '(Dialogo) A: "Do you speak English?" / B: "Yes, a little bit."', 'phrase', 'fc928c2b71b9b5a2cb8332b3b14910045e8f720c5c20b055bab9efd37d07fa1a', 'A1', true, 'easy', 'firebase', 3, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "frase_015", "note_culturale": ""}', NULL),
