    (50, '(Dialogo formale) A: "Saan esitellä rouva Bianchin." / B: "Hauska tutustua (Teihin)."', 'phrase', 'd614ea2e218f6ff335d53ec6f462f1054a6772b934bc452d9813e46c9a8bbb48', 'A1', true, 'easy', 'firebase', 2, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "frase_016", "note_culturale": ""}', NULL),
