    (53, '(Dialogo) A: "Kuinka vanha olet?" / B: "Olen kolmekymmentä (vuotta vanha)."', 'phrase', '1f0ff1df4ab5155163eabbae7419220fdc8c58132cdf0db51a7afd41ae9be57b', 'A1', true, 'easy', 'firebase', 2, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "frase_017", "note_culturale": ""}', NULL),
    (54, '(Dialogo) A: "How old are you?" / B: "I''m thirty (years old)."', 'phrase', 'c475fc17ba1985d634a3a4db0dc60b9255394468f8c479b5bbc3d673294b414b', 'A1', true, 'easy', 'firebase', 3, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "frase_017", "note_culturale": ""}', NULL),
    (55, '(Dialogo) A: "Studi o lavori?" / B: "Studio, sono all''università."', 'phrase', 'a67fabcb9b3a4fecee3053e7cffd6ea2912c47d4a50c3501f36d2c8f064a4f13', 'A1', true, 'easy', 'firebase', 1, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "frase_018", "note_culturale": ""}', NULL),
    (56, '(Dialogo) A: "Opiskeletko vai oletko töissä?" / B: "Opiskelen, olen yliopistossa."', 'phrase', '18b7416d177a33b79f9b2905763dc8745cb128f2170d8f375c4113ca3d0d92ca', 'A1', true, 'easy', 'firebase', 2, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "frase_018", "note_culturale": ""}', NULL),
    (57, '(Dialogo) A: "Do you study or work?" / B: "I study, I''m at university."', 'phrase', 'a352be038724f720ebb8c26e949dbd3aa61991c107d47bf1e59ae4de4f57201a', 'A1', true, 'easy', 'firebase', 3, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "frase_018", "note_culturale": ""}', NULL),
    (58, '(Dialogo) A: "Sei qui in vacanza?" / B: "Sì, esatto."', 'phrase', 'c2f0f9f5a0ea5cae036d26629fe5832583c8668bc824ed64d200caf9ffe03813', 'A1', true, 'easy', 'firebase', 1, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "frase_019", "note_culturale": ""}', NULL),
    (59, '(Dialogo) A: "Oletko täällä lomalla?" / B: "Kyllä, juuri niin."', 'phrase', '7bc9969734477c56b6c59f5797cfd690d4fca37f6c5d3edee3789549d7e7bf37', 'A1', true, 'easy', 'firebase', 2, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "frase_019", "note_culturale": ""}', NULL),
    (60, '(Dialogo) A: "Are you here on holiday?" / B: "Yes, that''s right."', 'phrase', '24c863c4d1c073f0dccc2fd1e7d9fb35a19f79e58f3f0cf8eaf98839e3bcd931', 'A1', true, 'easy', 'firebase', 3, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "frase_019", "note_culturale": ""}', NULL),
    (61, '(Dialogo) A: "Scusa, come hai detto che ti chiami?" / B: "Marco. M-A-R-C-O."', 'phrase', '97f8159a0f5491f7bf0f6746cf5ab1b994adbdf91d12a95b0c879d5ee3e4a552', 'A1', true, 'easy', 'firebase', 1, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "frase_020", "note_culturale": ""}', NULL),
    (62, '(Dialogo) A: "Anteeksi, mikä nimesi olikaan?" / B: "Marco. M-A-R-C-O."', 'phrase', '531a5ac94f304ea3ef045d14e403202da731cafa13e237c99fcc5bce2f0c87d7', 'A1', true, 'easy', 'firebase', 2, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "frase_020", "note_culturale": ""}', NULL),
    (63, '(Dialogo) A: "Sorry, what was your name again?" / B: "Marco. M-A-R-C-O."', 'phrase', 'e611c9a227f837114ac14043f07545bca4eb56eec83c350cebcf3b466e9301eb', 'A1', true, 'easy', 'firebase', 3, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "frase_020", "note_culturale": ""}', NULL),
    (64, '(Dialogo) A: "Ecco il tuo caffè." / B: "Grazie mille!" / A: "Non c''è di che."', 'phrase', 'cd6010d53b8de03035e4f7a0dfa0f5b02e67fcd4fbaae234fd92eeb9a93bb822', 'A1', true, 'easy', 'firebase', 1, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "frase_021", "note_culturale": ""}', NULL),
    (65, '(Dialogo) A: "Ole hyvä, kahvisi." / B: "Kiitos paljon!" / A: "Eipä kestä."', 'phrase', 'c2105d9216ff44b610d5fcd24200ed9917c68c786abc23406881856e696f8149', 'A1', true, 'easy', 'firebase', 2, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "frase_021", "note_culturale": ""}', NULL),
    (66, '(Dialogo) A: "Here is your coffee." / B: "Thanks a lot!" / A: "You''re welcome."', 'phrase', '9176ae42328017dcd9a05927a12fdd5355524cfd1a79eb25d66e9ef465219911', 'A1', true, 'easy', 'firebase', 3, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "frase_021", "note_culturale": ""}', NULL),
    (67, '(Dialogo) A: "Scusa, sono in ritardo!" / B: "Non fa niente."', 'phrase', 'bfb9fd42eb8ffe9c9751bcdd95d1757fb46287e5c537c53e8b175f501f58d549', 'A1', true, 'easy', 'firebase', 1, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "frase_022", "note_culturale": ""}', NULL),
    (68, '(Dialogo) A: "Anteeksi, olen myöhässä!" / B: "Ei se mitään."', 'phrase', '14375cf0d443827af4bed78d2a19d7ccfcffb017858e16ff24dcb553c723e37e', 'A1', true, 'easy', 'firebase', 2, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "frase_022", "note_culturale": ""}', NULL),
    (69, '(Dialogo) A: "Sorry, I''m late!" / B: "Never mind."', 'phrase', '0a672b75f5e64355631c05f417fcaee0fb2241b3fee9725627552c5f9640dc7a', 'A1', true, 'easy', 'firebase', 3, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "frase_022", "note_culturale": ""}', NULL),
    (70, '(Dialogo) A: "Ti offro un caffè." / B: "Oh, grazie! Troppo gentile!"', 'phrase', '1c2d31af597dd4aeaf6bf31d7697ba49e474d05f9c01fd7b0ac81ab8299d0675', 'A1', true, 'easy', 'firebase', 1, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "frase_023", "note_culturale": ""}', NULL),
    (71, '(Dialogo) A: "Tarjoan sinulle kahvin." / B: "Oi, kiitos! Onpa ystävällistä!"', 'phrase', '5113512ebb88f4398445250b8abcf9c92b5193dea6ac1061e8f3f50bc5e84e03', 'A1', true, 'easy', 'firebase', 2, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "frase_023", "note_culturale": ""}', NULL),
    (72, '(Dialogo) A: "I''ll buy you a coffee." / B: "Oh, thanks! That''s (too) kind of you!"', 'phrase', '73671ff00652e868bf6b067bac28e4c021c7e34e0409cd297581f5053401382f', 'A1', true, 'easy', 'firebase', 3, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "frase_023", "note_culturale": ""}', NULL),
    (73, '(Dialogo) A: "Permesso, scusi." / B: "Prego."', 'phrase', 'e46214ca3186c67c24862ee29c925bd96c9c3792e6d7c2e31e022c39a8812e75', 'A1', true, 'easy', 'firebase', 1, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "frase_024", "note_culturale": ""}', NULL),
    (74, '(Dialogo) A: "Anteeksi, saako mennä." / B: "Olkaa hyvä."', 'phrase', 'ca161a890d15f4ff73d591d7ff745ff9b66ae3d6e8b4efb10fcaaa3cc95365ff', 'A1', true, 'easy', 'firebase', 2, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "frase_024", "note_culturale": ""}', NULL),
    (75, '(Dialogo) A: "Excuse me." (per passare) / B: "Go ahead."', 'phrase', '51b29c168725991752581346d007829ba8d4892e68cb86869caccdd1eceb2a1c', 'A1', true, 'easy', 'firebase', 3, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "frase_024", "note_culturale": ""}', NULL),
    (76, '(Dialogo) A: "Mi passi il sale, per favore?" / B: "Certo, tieni."', 'phrase', '45f7f7d94af37bbff2e26bf26cf2f276cbdea9eec5ce788a43f338198de7be12', 'A1', true, 'easy', 'firebase', 1, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "frase_025", "note_culturale": ""}', NULL),
    (77, '(Dialogo) A: "Voisitko ojentaa suolan, kiitos?" / B: "Tottakai, ole hyvä."', 'phrase', '30b2d470fe049d246374ea58bdbfa3004173ff5526ce70d17e5371f58effeb5f', 'A1', true, 'easy', 'firebase', 2, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "frase_025", "note_culturale": ""}', NULL),
    (78, '(Dialogo) A: "Can you pass the salt, please?" / B: "Sure, here you go."', 'phrase', 'acf95f1afa47af4f37bf4f03137706b92c710299e72ff98bd86cb4a18864d2bd', 'A1', true, 'easy', 'firebase', 3, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "frase_025", "note_culturale": ""}', NULL),
    (79, '(Dialogo) A: "Scusa, posso usare il tuo telefono?" / B: "Fai pure."', 'phrase', '96d0e51ecedd707b42487025b1dfe02c270595adb628cf4696c3decb81c93598', 'A1', true, 'easy', 'firebase', 1, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "frase_026", "note_culturale": ""}', NULL),
    (80, '(Dialogo) A: "Anteeksi, saanko käyttää puhelintasi?" / B: "Anna mennä vaan."', 'phrase', '761e9010f48c7ceebe9e7431a09aea4ab421305571b3ec99211ccbc8abebde92', 'A1', true, 'easy', 'firebase', 2, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "frase_026", "note_culturale": ""}', NULL),
    (81, '(Dialogo) A: "Sorry, can I use your phone?" / B: "Go ahead."', 'phrase', 'bc8e6de7dd2c93b4cc62f4ac5af04a6cb491bc436450a9336c2f297c1f42df4d', 'A1', true, 'easy', 'firebase', 3, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "frase_026", "note_culturale": ""}', NULL),
    (82, '(Dialogo) A: "Ho finito, grazie per l''aiuto!" / B: "Figurati!"', 'phrase', 'a324227805c7155deb1b262624640447e5599007d972a14b4587d6ef3e7ab8ee', 'A1', true, 'easy', 'firebase', 1, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "frase_027", "note_culturale": "''Figurati!'' è un modo informale e comune per rispondere ''prego'', equivalente a ''No problem!'' o ''Eipä kestä!''."}', NULL),
    (83, '(Dialogo) A: "Olen valmis, kiitos avusta!" / B: "Eipä kestä!"', 'phrase', '467cf748c9c9a2fccf815916cb50b50d8a0115aec86cf53bc84b1d578bef4ad1', 'A1', true, 'easy', 'firebase', 2, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "frase_027", "note_culturale": "''Figurati!'' è un modo informale e comune per rispondere ''prego'', equivalente a ''No problem!'' o ''Eipä kestä!''."}', NULL),
    (84, '(Dialogo) A: "I''m done, thanks for the help!" / B: "No problem!"', 'phrase', 'c1f93cea9442de4aa09ca2239d051f574e9981531cb396c74bb0a447d923f3fc', 'A1', true, 'easy', 'firebase', 3, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "frase_027", "note_culturale": "''Figurati!'' è un modo informale e comune per rispondere ''prego'', equivalente a ''No problem!'' o ''Eipä kestä!''."}', NULL),
    (85, '(Dialogo) A: "Ah, ho dimenticato il portafoglio." / B: "Tranquillo, offro io."', 'phrase', '7b5a787cbdfeafcd6b0e5214b2c4aa0e8d0b4a5b8f2a25aed6b12ac0698dcc57', 'A1', true, 'easy', 'firebase', 1, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "frase_028", "note_culturale": "Offrirsi di pagare. ''Tranquillo'' / ''Ei hätää'' (Nessun problema). ''Offro io'' (IT) e ''It''s on me'' (EN) sono idiomi B1 perfetti."}', NULL),
    (86, '(Dialogo) A: "Voi, unohdin lompakon." / B: "Ei hätää, minä tarjoan."', 'phrase', '3101a9a8d4f2673d76bee694b06f911d0de37d9916449bc05a803df0fadf1f53', 'A1', true, 'easy', 'firebase', 2, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "frase_028", "note_culturale": "Offrirsi di pagare. ''Tranquillo'' / ''Ei hätää'' (Nessun problema). ''Offro io'' (IT) e ''It''s on me'' (EN) sono idiomi B1 perfetti."}', NULL),
    (87, '(Dialogo) A: "Ah, I forgot my wallet." / B: "Don''t worry, it''s on me."', 'phrase', '190df54a007cfc1a7da46a08f48c057f33514375e1dec3050e23931b420351b3', 'A1', true, 'easy', 'firebase', 3, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "frase_028", "note_culturale": "Offrirsi di pagare. ''Tranquillo'' / ''Ei hätää'' (Nessun problema). ''Offro io'' (IT) e ''It''s on me'' (EN) sono idiomi B1 perfetti."}', NULL),
    (88, '(Dialogo) A: "Ti disturbo?" / B: "No, affatto! Dimmi pure."', 'phrase', '8ad76b2499757dad2fae1900a1a49d02ffde849eabb07007a43e42d08aec945d', 'A1', true, 'easy', 'firebase', 1, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "frase_029", "note_culturale": "Modo educato per iniziare una conversazione. ''Dimmi pure'' / ''Kerro pois'' (Racconta via) / ''What''s up?'' sono inviti a parlare."}', NULL),
    (89, '(Dialogo) A: "Häiritsenkö?" / B: "Et lainkaan! Kerro pois."', 'phrase', 'a5da71bfbaaf6e061149832b4a0c6737f3f0691c9ba237259f75820b29095e66', 'A1', true, 'easy', 'firebase', 2, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "frase_029", "note_culturale": "Modo educato per iniziare una conversazione. ''Dimmi pure'' / ''Kerro pois'' (Racconta via) / ''What''s up?'' sono inviti a parlare."}', NULL),
    (90, '(Dialogo) A: "Am I disturbing you?" / B: "Not at all! What''s up?"', 'phrase', 'd81eef2130bec280caf925f59b003e83831cdab27aeefc7d5261b0ddb60b2390', 'A1', true, 'easy', 'firebase', 3, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "frase_029", "note_culturale": "Modo educato per iniziare una conversazione. ''Dimmi pure'' / ''Kerro pois'' (Racconta via) / ''What''s up?'' sono inviti a parlare."}', NULL),
    (91, '(Dialogo) A: "Salute!" (dopo uno starnuto) / B: "Grazie."', 'phrase', '4cbb2cc54ffae6b3581941156906cee43d7356cfde78e7e420ce44d2a539361a', 'A1', true, 'easy', 'firebase', 1, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "frase_030", "note_culturale": "Risposta culturale standard a uno starnuto. ''Salute!'' (IT) e ''Terveydeksi!'' (FI) augurano salute, ''Bless you!'' (EN) invoca una benedizione."}', NULL),
    (92, '(Dialogo) A: "Terveydeksi!" / B: "Kiitos."', 'phrase', '75176f9f0171b0def3998daa0968a0d9b17d41ac7716a14645b70b581d474e34', 'A1', true, 'easy', 'firebase', 2, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "frase_030", "note_culturale": "Risposta culturale standard a uno starnuto. ''Salute!'' (IT) e ''Terveydeksi!'' (FI) augurano salute, ''Bless you!'' (EN) invoca una benedizione."}', NULL),
    (93, '(Dialogo) A: "Bless you!" / B: "Thank you."', 'phrase', '6d9464303b9fbeabfb15759c52077a92722f4770d58ba755379abf32cdd76184', 'A1', true, 'easy', 'firebase', 3, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "frase_030", "note_culturale": "Risposta culturale standard a uno starnuto. ''Salute!'' (IT) e ''Terveydeksi!'' (FI) augurano salute, ''Bless you!'' (EN) invoca una benedizione."}', NULL),
    (94, '(Dialogo) A: "Buon appetito!" / B: "Grazie, altrettanto!"', 'phrase', '53494113e5a5dac40e6085648cffb18c4a6627fe32308585e191749f6972d8e9', 'A1', true, 'easy', 'firebase', 1, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "frase_031", "note_culturale": "Augurio standard prima di mangiare. IT e FI augurano ''buon appetito'', EN ''goditi il pasto''. La risposta (''Altrettanto'' / ''Samoin'') è identica."}', NULL),
    (95, '(Dialogo) A: "Hyvää ruokahalua!" / B: "Kiitos, samoin!"', 'phrase', 'c81f649f8ed02bae0d8ea375db232fe4d9a00d7bf7288e0e68081e5685b6473e', 'A1', true, 'easy', 'firebase', 2, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "frase_031", "note_culturale": "Augurio standard prima di mangiare. IT e FI augurano ''buon appetito'', EN ''goditi il pasto''. La risposta (''Altrettanto'' / ''Samoin'') è identica."}', NULL),
    (96, '(Dialogo) A: "Enjoy your meal!" / B: "Thanks, you too!"', 'phrase', '98c4a737690e7b671facc53f4927dd493c54d5c63e6ab14c00734c5f09a660ba', 'A1', true, 'easy', 'firebase', 3, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "frase_031", "note_culturale": "Augurio standard prima di mangiare. IT e FI augurano ''buon appetito'', EN ''goditi il pasto''. La risposta (''Altrettanto'' / ''Samoin'') è identica."}', NULL),
    (97, '(Dialogo) A: "Scusa, ho rotto il tuo bicchiere!" / B: "Pazienza. Non era importante."', 'phrase', 'b6802149f8a8a823eab4d1ce02fef5b0a49741b141671f75c5804e18c5d7ba68', 'A1', true, 'easy', 'firebase', 1, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "frase_032", "note_culturale": "Reazione a un piccolo incidente. ''Pazienza'' / ''Ei voi mitään'' (Non si può [fare] niente) / ''It can''t be helped'' esprimono rassegnazione."}', NULL),
    (98, '(Dialogo) A: "Anteeksi, rikoin lasisi!" / B: "Ei voi mitään. Ei se ollut tärkeä."', 'phrase', 'fd0b04ffe5a87e64a1ac07ced632265f980f001629648a23b15f7e2d789c5d85', 'A1', true, 'easy', 'firebase', 2, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "frase_032", "note_culturale": "Reazione a un piccolo incidente. ''Pazienza'' / ''Ei voi mitään'' (Non si può [fare] niente) / ''It can''t be helped'' esprimono rassegnazione."}', NULL),
    (99, '(Dialogo) A: "I''m sorry, I broke your glass!" / B: "It can''t be helped. It wasn''t important."', 'phrase', 'c32a290b1588b4ac5c8faec9f199b05e4a2fb926b069ec7a7e1ff0000b3ee515', 'A1', true, 'easy', 'firebase', 3, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "frase_032", "note_culturale": "Reazione a un piccolo incidente. ''Pazienza'' / ''Ei voi mitään'' (Non si può [fare] niente) / ''It can''t be helped'' esprimono rassegnazione."}', NULL),
    (100, '(Dialogo) A: "Buongiorno, cosa Le porto?" / B: "Un caffè, per favore."', 'phrase', '00838d6c2df30bde2a61feb988604143c7966f3d829c46392580a78d8860c6e0', 'A1', true, 'easy', 'firebase', 1, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "frase_033", "note_culturale": "Dialogo base formale per ordinare al bar."}', NULL),
    (101, '(Dialogo) A: "Hyvää huomenta, mitä teille saisi olla?" / B: "Yksi kahvi, kiitos."', 'phrase', '41214e53cce45f58a2e7d1d7a7cf4b706c26f74ceec555c3badd7b4c33489808', 'A1', true, 'easy', 'firebase', 2, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "frase_033", "note_culturale": "Dialogo base formale per ordinare al bar."}', NULL),
    (102, '(Dialogo) A: "Good morning, what can I get you?" / B: "A coffee, please."', 'phrase', '4380615f17e11b247b1332f49c06d1c257189c10579972acc368fa8f65af0029', 'A1', true, 'easy', 'firebase', 3, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "frase_033", "note_culturale": "Dialogo base formale per ordinare al bar."}', NULL),
    (103, '(Dialogo) A: "Prego, ecco il menù." / B: "Grazie. Posso avere dell''acqua?" / A: "Naturale o frizzante?"', 'phrase', '2db3a00681d2808a7a0597c8976a8baf3037585e328638801f2baee5721c45bc', 'A1', true, 'easy', 'firebase', 1, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "frase_034", "note_culturale": "Richiesta d''acqua e la domanda standard che ne consegue."}', NULL),
    (104, '(Dialogo) A: "Olkaa hyvä, tässä menu." / B: "Kiitos. Saisinko vettä?" / A: "Hiilihapollista vai hiilihapotonta?"', 'phrase', '13eafe7c181f18dc5dc6fc1531b0ad4f9f704c066ca504a95f75177a97e088f6', 'A1', true, 'easy', 'firebase', 2, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "frase_034", "note_culturale": "Richiesta d''acqua e la domanda standard che ne consegue."}', NULL),
    (105, '(Dialogo) A: "Here you go, the menu." / B: "Thanks. Can I get some water?" / A: "Still or sparkling?"', 'phrase', '1d078b09f61fb5487f4d4d14950cdf48994308e93f7d5fb7396d4f664486420f', 'A1', true, 'easy', 'firebase', 3, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "frase_034", "note_culturale": "Richiesta d''acqua e la domanda standard che ne consegue."}', NULL),
    (106, '(Dialogo) A: "Tutto bene qui?" / B: "Sì, grazie. Il conto, per favore."', 'phrase', '6b3ae3a59d20977fb665a5f885327fa9a0589374ad4787c1b8149b0f16dddea3', 'A1', true, 'easy', 'firebase', 1, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "frase_035", "note_culturale": "Come chiedere il conto. Nota la differenza culturale finlandese: il cameriere chiede se il cibo è buono (''Maistuuko?'')."}', NULL),
    (107, '(Dialogo) A: "Maistuuko ruoka?" (lett. "Il cibo ha un buon sapore?") / B: "Kyllä, kiitos. Lasku, kiitos."', 'phrase', 'c6089f18154fcd9806663085d3c3c6c49f545abae81a93d69f5961586020627b', 'A1', true, 'easy', 'firebase', 2, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "frase_035", "note_culturale": "Come chiedere il conto. Nota la differenza culturale finlandese: il cameriere chiede se il cibo è buono (''Maistuuko?'')."}', NULL),
    (108, '(Dialogo) A: "Is everything alright here?" / B: "Yes, thanks. The bill (check), please."', 'phrase', 'fa7ec8b42cea044b73f5d976b58282e6e376acdbd399b1f1d821fd938b670044', 'A1', true, 'easy', 'firebase', 3, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "frase_035", "note_culturale": "Come chiedere il conto. Nota la differenza culturale finlandese: il cameriere chiede se il cibo è buono (''Maistuuko?'')."}', NULL),
    (109, '(Dialogo) A: "Posso pagare con la carta?" / B: "Certo."', 'phrase', '2edc0b37de86848724f17133dbf004f3ada193e04e9d3a752a6dfc03c61ef78f', 'A1', true, 'easy', 'firebase', 1, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "frase_036", "note_culturale": "Richiesta standard per il metodo di pagamento."}', NULL),
    (110, '(Dialogo) A: "Voinko maksaa kortilla?" / B: "Toki."', 'phrase', 'd37a9ee2c01b989bca8e818976085bae1d9ddd53234500dcf5297ee7779ac5af', 'A1', true, 'easy', 'firebase', 2, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "frase_036", "note_culturale": "Richiesta standard per il metodo di pagamento."}', NULL),
    (111, '(Dialogo) A: "Can I pay by card?" / B: "Of course."', 'phrase', '2fc2ed6b93ecf2bbbb0cada71da03a950502be7f2e8f7d0f64f5cd0372edb04b', 'A1', true, 'easy', 'firebase', 3, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "frase_036", "note_culturale": "Richiesta standard per il metodo di pagamento."}', NULL),
    (112, '(Dialogo) A: "Scusi, è libero questo tavolo?" / B: "Sì, accomodatevi pure."', 'phrase', '101e9db5debd36d8d8e7db4331ed4547cc1c2fe8a77b144eb12c8930a0cc9296', 'A1', true, 'easy', 'firebase', 1, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "frase_037", "note_culturale": "Chiedere un tavolo e la risposta di ''accomodarsi''."}', NULL),
    (113, '(Dialogo) A: "Anteeksi, onko tämä pöytä vapaa?" / B: "Kyllä, olkaa hyvä."', 'phrase', 'ad07d2fb4d24c194e0ca79e65199ea06351f89d77d96dcb769d3db89ad4360bd', 'A1', true, 'easy', 'firebase', 2, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "frase_037", "note_culturale": "Chiedere un tavolo e la risposta di ''accomodarsi''."}', NULL),
    (114, '(Dialogo) A: "Excuse me, is this table free?" / B: "Yes, please, have a seat."', 'phrase', 'f7f570abaaf22a0b14dee0e6f326387057d6d34789845bb9fa08b9618cdca44b', 'A1', true, 'easy', 'firebase', 3, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "frase_037", "note_culturale": "Chiedere un tavolo e la risposta di ''accomodarsi''."}', NULL),
    (115, '(Dialogo) A: "Cosa prendi da bere?" / B: "Per me una birra piccola."', 'phrase', '0e9d2c803b9c5984354bd78290256f5ff32be86adcb524039355d6b775007dd9', 'A1', true, 'easy', 'firebase', 1, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "frase_038", "note_culturale": "Ordinazione informale di bevande tra amici."}', NULL),
    (116, '(Dialogo) A: "Mitä otat juotavaksi?" / B: "Minulle pieni olut."', 'phrase', '94012cd8a95886e102a3801196b2d8caae9f9a930bb66b86f19d457448133b3c', 'A1', true, 'easy', 'firebase', 2, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "frase_038", "note_culturale": "Ordinazione informale di bevande tra amici."}', NULL),
    (117, '(Dialogo) A: "What are you having to drink?" / B: "I''ll have a small beer."', 'phrase', '420c0e48621c088ce5186809d2a35db245fda65e499a2236156ea28865c1dcb0', 'A1', true, 'easy', 'firebase', 3, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "frase_038", "note_culturale": "Ordinazione informale di bevande tra amici."}', NULL),
    (118, '(Dialogo) A: "Vuoi un altro caffè?" / B: "No grazie, sono a posto così."', 'phrase', 'c1732c2ae47dbf5ead486f213ffe7d21f13c979fe37e689881124338ac740bf8', 'A1', true, 'easy', 'firebase', 1, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "frase_039", "note_culturale": "Modo naturale per rifiutare un''offerta. ''Sono a posto così'' / ''Tämä riittää'' (Questo è sufficiente) / ''I''m good'' sono equivalenti idiomatici."}', NULL),
    (119, '(Dialogo) A: "Haluatko toisen kahvin?" / B: "Ei kiitos, tämä riittää."', 'phrase', '3688550f77d1fec67e204dc96f934b862e225b4764921338e7ad2058929c7d21', 'A1', true, 'easy', 'firebase', 2, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "frase_039", "note_culturale": "Modo naturale per rifiutare un''offerta. ''Sono a posto così'' / ''Tämä riittää'' (Questo è sufficiente) / ''I''m good'' sono equivalenti idiomatici."}', NULL),
    (120, '(Dialogo) A: "Want another coffee?" / B: "No thanks, I''m good."', 'phrase', 'c3c8c8eae8e38fccb4d24a511793fff95a116ebe8ccd7d5964ddd8aab7d0cf6d', 'A1', true, 'easy', 'firebase', 3, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "frase_039", "note_culturale": "Modo naturale per rifiutare un''offerta. ''Sono a posto così'' / ''Tämä riittää'' (Questo è sufficiente) / ''I''m good'' sono equivalenti idiomatici."}', NULL),
    (121, '(Dialogo) A: "Vi porto qualcosa?" / B: "Per ora niente, grazie. Diamo solo un''occhiata."', 'phrase', 'ae0dd4955c9fc03a42ff8f128471bf3cf7450c6f97b136e7506fc40b1fce1724', 'A1', true, 'easy', 'firebase', 1, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "frase_040", "note_culturale": "Risposta standard per prendere tempo prima di ordinare."}', NULL),
    (122, '(Dialogo) A: "Toisinko teille jotain?" / B: "Ei mitään tällä hetkellä, kiitos. Katsellaan rauhassa."', 'phrase', '2e6e84f1ebbf6abaedc7bd8d8f6b5877dc6084c224bbf8525d4ee1a502ff1073', 'A1', true, 'easy', 'firebase', 2, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "frase_040", "note_culturale": "Risposta standard per prendere tempo prima di ordinare."}', NULL),
    (123, '(Dialogo) A: "Can I get you anything?" / B: "Nothing for now, thanks. We''re just looking."', 'phrase', '4941abf7727df6af2c2a6c8e302b17bd456db0b872ffbef153cf6c3dc2ee589c', 'A1', true, 'easy', 'firebase', 3, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "frase_040", "note_culturale": "Risposta standard per prendere tempo prima di ordinare."}', NULL),
    (124, '(Dialogo) A: "Scusi, c''è un bagno qui?" / B: "Sì, in fondo a destra."', 'phrase', '76e748abc87995f38dbda3a530b3d4f20e8622a32537e43b79388a3fef534363', 'A1', true, 'easy', 'firebase', 1, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "frase_041", "note_culturale": "Richiesta di base per i servizi e indicazioni semplici."}', NULL),
    (125, '(Dialogo) A: "Anteeksi, onko täällä vessaa?" / B: "Kyllä, perällä oikealla."', 'phrase', '30d9b1cd8a38ef7708fab0fe34a1bd5f5b3a7acee3c7dbf8429c7dc276e25244', 'A1', true, 'easy', 'firebase', 2, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "frase_041", "note_culturale": "Richiesta di base per i servizi e indicazioni semplici."}', NULL),
    (126, '(Dialogo) A: "Excuse me, is there a restroom (bathroom) here?" / B: "Yes, down the hall to the right."', 'phrase', '84cdb16c1d3075f4adbb52c2548fb0eec17b358b9d5d51a95d9dffcc934e79bc', 'A1', true, 'easy', 'firebase', 3, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "frase_041", "note_culturale": "Richiesta di base per i servizi e indicazioni semplici."}', NULL),
    (127, '(Dialogo) A: "Pagate insieme o alla romana?" / B: "Facciamo conti separati."', 'phrase', '9a729fc5d7cce75b991306c15a5fa8b23f1622991dfa1b291e78d12894cf80c2', 'A1', true, 'easy', 'firebase', 1, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "frase_042", "note_culturale": "Gestione del pagamento di gruppo. L''italiano usa l''idioma ''alla romana'', mentre FI/EN sono più diretti (''erikseen'' / ''separately'')."}', NULL),
    (128, '(Dialogo) A: "Maksatteko yhdessä vai erikseen?" / B: "Maksamme erikseen."', 'phrase', 'd82ed34641f2042e82c62768bcdc10ad125b07e093405c7fb24354260257a84c', 'A1', true, 'easy', 'firebase', 2, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "frase_042", "note_culturale": "Gestione del pagamento di gruppo. L''italiano usa l''idioma ''alla romana'', mentre FI/EN sono più diretti (''erikseen'' / ''separately'')."}', NULL),
    (129, '(Dialogo) A: "Are you paying together or separately?" / B: "We''ll pay separately."', 'phrase', '0d6b4a276934f261373d8f84ed27a13fd8a9c9ab74139153fb453549ee1c17bd', 'A1', true, 'easy', 'firebase', 3, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "frase_042", "note_culturale": "Gestione del pagamento di gruppo. L''italiano usa l''idioma ''alla romana'', mentre FI/EN sono più diretti (''erikseen'' / ''separately'')."}', NULL),
    (130, '(Dialogo) A: "Vuoi il cornetto vuoto o alla crema?" / B: "Vuoto, grazie."', 'phrase', '60ec88969788fa18e5b2a6651491433e58fcef724410bea26ddc169f3632d8d9', 'A1', true, 'easy', 'firebase', 1, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "frase_043", "note_culturale": "Ordinazione di un cornetto. ''Vuoto'' (IT), ''ilman täytettä'' (FI, ''senza ripieno'') e ''plain'' (EN) sono gli equivalenti corretti."}', NULL),
    (131, '(Dialogo) A: "Haluatko voisarven ilman täytettä vai kreemitäytteellä?" / B: "Ilman täytettä, kiitos."', 'phrase', '800da76ee4ee5b70a2ab2c825dc97612e9c3f4f02374088e33e105e4eb3454a0', 'A1', true, 'easy', 'firebase', 2, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "frase_043", "note_culturale": "Ordinazione di un cornetto. ''Vuoto'' (IT), ''ilman täytettä'' (FI, ''senza ripieno'') e ''plain'' (EN) sono gli equivalenti corretti."}', NULL),
    (132, '(Dialogo) A: "Do you want the croissant plain or with cream?" / B: "Plain, please."', 'phrase', 'a21520eeab98e20b47b85a05807633a611e0ee99d727aebb8bb13f11fd33b247', 'A1', true, 'easy', 'firebase', 3, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "frase_043", "note_culturale": "Ordinazione di un cornetto. ''Vuoto'' (IT), ''ilman täytettä'' (FI, ''senza ripieno'') e ''plain'' (EN) sono gli equivalenti corretti."}', NULL),
    (133, '(Dialogo) A: "Da mangiare?" / B: "Solo da bere, grazie."', 'phrase', 'ad50d8f0e2cf8df9edc7fa738828fc79c8c309a35ab943e4af95455f595ae561', 'A1', true, 'easy', 'firebase', 1, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "frase_044", "note_culturale": "Domanda e risposta molto comune al bar."}', NULL),
    (134, '(Dialogo) A: "Saisiko olla ruokaa?" / B: "Pelkkää juotavaa, kiitos."', 'phrase', '69425dd351e10101b017859cf99830194dbf194dd2689854afd8c999fad3ed1b', 'A1', true, 'easy', 'firebase', 2, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "frase_044", "note_culturale": "Domanda e risposta molto comune al bar."}', NULL),
    (135, '(Dialogo) A: "Anything to eat?" / B: "Just drinks, thanks."', 'phrase', '10b5ba80f51c84a0e85a294b5050646728c04c2a072946e3b57b6924c8665360', 'A1', true, 'easy', 'firebase', 3, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "frase_044", "note_culturale": "Domanda e risposta molto comune al bar."}', NULL),
    (136, '(Dialogo) A: "Scusi, non ho capito." / B: "Non si preoccupi, ripeto."', 'phrase', 'cf1d8adff22b068f61f594f940dfec83b8e117712e4f117b7a3ef69ca02fceff', 'A1', true, 'easy', 'firebase', 1, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "frase_045", "note_culturale": "Esprimere incomprensione e la reazione standard."}', NULL),
    (137, '(Dialogo) A: "Anteeksi, en ymmärtänyt." / B: "Ei hätää, toistan."', 'phrase', '67439efed9e39acd3c760832eb26fc260b569c446e99b571084db74b766e3454', 'A1', true, 'easy', 'firebase', 2, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "frase_045", "note_culturale": "Esprimere incomprensione e la reazione standard."}', NULL),
    (138, '(Dialogo) A: "Sorry, I didn''t understand." / B: "No worries, I''ll repeat."', 'phrase', 'c4fba7463bafeef3543d1ee51bac75c51100ac63a2f68fb070a46411712460e1', 'A1', true, 'easy', 'firebase', 3, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "frase_045", "note_culturale": "Esprimere incomprensione e la reazione standard."}', NULL),
    (139, '(Dialogo) A: "Parla troppo velocemente." / B: "Oh, scusi. Più piano?"', 'phrase', 'd8da6015546662c083463534be6997bc25c6c3eff1062b8394f770d1261e9e25', 'A1', true, 'easy', 'firebase', 1, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "frase_046", "note_culturale": "Richiesta comune quando si impara una lingua. La risposta finlandese (''Parlo più lentamente?'') è una forma interrogativa naturale."}', NULL),
    (140, '(Dialogo) A: "Puhutte liian nopeasti." / B: "Voi anteeksi, puhunko hitaammin?"', 'phrase', '9cde51295eb19b5236888708eeb6dcf465cbc8fa758ad376e1b796a14488cf5a', 'A1', true, 'easy', 'firebase', 2, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "frase_046", "note_culturale": "Richiesta comune quando si impara una lingua. La risposta finlandese (''Parlo più lentamente?'') è una forma interrogativa naturale."}', NULL),
    (141, '(Dialogo) A: "You''re speaking too fast." / B: "Oh, sorry. More slowly?"', 'phrase', 'dfc796b6eb362f377bf37f43ff6f029772c0c347d5c6fdc3158e2bbc35a9372a', 'A1', true, 'easy', 'firebase', 3, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "frase_046", "note_culturale": "Richiesta comune quando si impara una lingua. La risposta finlandese (''Parlo più lentamente?'') è una forma interrogativa naturale."}', NULL),
    (142, '(Dialogo) A: "Come si dice ''treno'' in finlandese?" / B: "Si dice ''juna''."', 'phrase', '6583ef884dc22385054a95aacd78c2c08f1884b19abcd6f709fa3b4d38edeef0', 'A1', true, 'easy', 'firebase', 1, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "frase_047", "note_culturale": "Domanda base per imparare un nuovo vocabolo."}', NULL),
    (143, '(Dialogo) A: "Miten sanottaan ''treno'' suomeksi?" / B: "Se on ''juna''."', 'phrase', '3d6b650dd9b50c1947136181ecb079c061822b496c00396ee559075eb086f06f', 'A1', true, 'easy', 'firebase', 2, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "frase_047", "note_culturale": "Domanda base per imparare un nuovo vocabolo."}', NULL),
    (144, '(Dialogo) A: "How do you say ''treno'' in Finnish?" / B: "You say ''juna''."', 'phrase', '096340377805963b089998adc0935a4155b0152121780a8f02f82cd1ab4249cb', 'A1', true, 'easy', 'firebase', 3, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "frase_047", "note_culturale": "Domanda base per imparare un nuovo vocabolo."}', NULL),
    (145, '(Dialogo) A: "Cosa significa ''kiitos''?" / B: "Vuol dire ''grazie''."', 'phrase', '29f37c8c4ce99cfd4bd3faac088f7683934511fb54d3b12bea2e7539e8256f32', 'A1', true, 'easy', 'firebase', 1, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "frase_048", "note_culturale": "Domanda base per capire il significato di una parola."}', NULL),
    (146, '(Dialogo) A: "Mitä ''kiitos'' tarkoittaa?" / B: "Se tarkoittaa ''grazie''."', 'phrase', 'b48aee4b8d995e1d9b24f7013092c9ff4783c0deaa03135fc4e3f8f4d3b9088b', 'A1', true, 'easy', 'firebase', 2, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "frase_048", "note_culturale": "Domanda base per capire il significato di una parola."}', NULL),
    (147, '(Dialogo) A: "What does ''kiitos'' mean?" / B: "It means ''thank you''."', 'phrase', 'de1704a5af86f2bdcd5abe7453a1130e34f84060add536bfd508d4b00510574d', 'A1', true, 'easy', 'firebase', 3, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "frase_048", "note_culturale": "Domanda base per capire il significato di una parola."}', NULL),
    (148, '(Dialogo) A: "Scusi, mi sono perso." / B: "Dove deve andare?"', 'phrase', 'd8ff8d23960d0e8bebf90035e53e0489e814de98bc2efba062af44cbaeff41c5', 'A1', true, 'easy', 'firebase', 1, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "frase_049", "note_culturale": "Espressione fondamentale per chiedere aiuto quando ci si perde."}', NULL),
    (149, '(Dialogo) A: "Anteeksi, olen eksynyt." / B: "Mihin teidän pitää mennä?"', 'phrase', 'dd4e1eeaf45b00bbc9607b282b1b04288f829b90710bacd43706ae2120ba6b9e', 'A1', true, 'easy', 'firebase', 2, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "frase_049", "note_culturale": "Espressione fondamentale per chiedere aiuto quando ci si perde."}', NULL),
    (150, '(Dialogo) A: "Excuse me, I''m lost." / B: "Where do you need to go?"', 'phrase', 'cc0f2af541b5cb82397e7813abdf3af5035d98e5b3b6a3a41e35b806c7118376', 'A1', true, 'easy', 'firebase', 3, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "frase_049", "note_culturale": "Espressione fondamentale per chiedere aiuto quando ci si perde."}', NULL),
    (151, '(Dialogo) A: "Aiuto! Ho perso il portafoglio!" / B: "Calma, chiamo la sicurezza."', 'phrase', '234b53b0abdbea633135ba51a8336ce872082c7e623475648dbadb7b34584c54', 'A1', true, 'easy', 'firebase', 1, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "frase_050", "note_culturale": "Richiesta di aiuto in una situazione di emergenza (furto/smarrimento)."}', NULL),
    (152, '(Dialogo) A: "Apua! Kadotin lompakkoni!" / B: "Rauhoitu, kutsun vartijan."', 'phrase', 'e1b2a646abc10629cce9e484b0f43aaafb74104aacbf4b1be90ac0f03c722f4f', 'A1', true, 'easy', 'firebase', 2, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "frase_050", "note_culturale": "Richiesta di aiuto in una situazione di emergenza (furto/smarrimento)."}', NULL),
    (153, '(Dialogo) A: "Help! I''ve lost my wallet!" / B: "Calm down, I''ll call security."', 'phrase', 'fb8bb3525b1911891157350e63649ed8c850830df9ca387bbb6bc261792ad346', 'A1', true, 'easy', 'firebase', 3, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "frase_050", "note_culturale": "Richiesta di aiuto in una situazione di emergenza (furto/smarrimento)."}', NULL),
    (154, '(Dialogo) A: "Scusa, sai dov''è la stazione?" / B: "Mi dispiace, non sono di qui."', 'phrase', 'c05e68dd2516712e3408718f4b30825fe38d39a30f9887b89642dff265bd937a', 'A1', true, 'easy', 'firebase', 1, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "frase_051", "note_culturale": "Risposta standard per quando non si sa dare un''indicazione."}', NULL),
    (155, '(Dialogo) A: "Anteeksi, tiedätkö missä asema on?" / B: "Valitettavasti en ole täältä kotoisin."', 'phrase', 'aa349a74c7cf5f13a920675547cbaffdda74c2d2c338b79789afb2f3f469d552', 'A1', true, 'easy', 'firebase', 2, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "frase_051", "note_culturale": "Risposta standard per quando non si sa dare un''indicazione."}', NULL),
    (156, '(Dialogo) A: "Excuse me, do you know where the station is?" / B: "I''m sorry, I''m not from around here."', 'phrase', 'b10a9b2b18c8603ee8fa2bb665270417b93d72b93e19557c49007580bf6ac2b5', 'A1', true, 'easy', 'firebase', 3, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "frase_051", "note_culturale": "Risposta standard per quando non si sa dare un''indicazione."}', NULL),
    (157, '(Dialogo) A: "Puoi scriverlo, per favore?" / B: "Certo, un attimo."', 'phrase', '4807356c58a898b0dce4bd3849d2d5d6559401d9aa610c9b7887f3275c05ffc5', 'A1', true, 'easy', 'firebase', 1, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "frase_052", "note_culturale": "Richiesta utile quando non si capisce la pronuncia."}', NULL),
    (158, '(Dialogo) A: "Voitko kirjoittaa sen, kiitos?" / B: "Toki, hetkinen."', 'phrase', '16071772dcd8ab63eab63dfb4098c405fe10134c8d3fe49bcc203272bfb83976', 'A1', true, 'easy', 'firebase', 2, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "frase_052", "note_culturale": "Richiesta utile quando non si capisce la pronuncia."}', NULL),
    (159, '(Dialogo) A: "Can you write it down, please?" / B: "Sure, just a moment."', 'phrase', 'cee3051c3486aff5e201bc66021e907c2f477d99f9733b8625b4e6eaa47c6497', 'A1', true, 'easy', 'firebase', 3, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "frase_052", "note_culturale": "Richiesta utile quando non si capisce la pronuncia."}', NULL),
    (160, '(Dialogo) A: "Il mio telefono è morto. Posso usare il tuo?" / B: "Certo, tieni."', 'phrase', 'da73f415dbb943b7d487be9c94aefc42f5e1c737da0b9009e544c40aa125564b', 'A1', true, 'easy', 'firebase', 1, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "frase_053", "note_culturale": "L''idioma ''è morto'' / ''is dead'' si traduce in finlandese con la forma letterale ''la batteria è finita'' (akku loppui)."}', NULL),
    (161, '(Dialogo) A: "Puhelimestani loppui akku. Saanko käyttää sinun puhelintasi?" / B: "Tottakai, ole hyvä."', 'phrase', '837e893927edf14efd7ba36ab3a8bb23b59da8ef81a9f15fbdb946c4b3456fb8', 'A1', true, 'easy', 'firebase', 2, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "frase_053", "note_culturale": "L''idioma ''è morto'' / ''is dead'' si traduce in finlandese con la forma letterale ''la batteria è finita'' (akku loppui)."}', NULL),
    (162, '(Dialogo) A: "My phone is dead. Can I use yours?"', 'phrase', 'e22997d27bd102ff53fb575f13c00d3a6ef93580549e2fe33f99015616699370', 'A1', true, 'easy', 'firebase', 3, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "frase_053", "note_culturale": "L''idioma ''è morto'' / ''is dead'' si traduce in finlandese con la forma letterale ''la batteria è finita'' (akku loppui)."}', NULL),
    (163, '(Dialogo) A: "Che ore sono?" / B: "Sono le tre in punto."', 'phrase', '423fde37a0ebf35c55731231e433a719ea182539863f7c2f4f2e68de053d0a77', 'A1', true, 'easy', 'firebase', 1, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "frase_055", "note_culturale": "Chiedere l''ora. ''In punto'' (IT) e ''tasan'' (FI) sono enfasi comuni che l''inglese omette (semplicemente ''o''clock'')."}', NULL),
    (164, '(Dialogo) A: "Mitä kello on?" / B: "Se on tasan kolme."', 'phrase', '204579659c6aff6d07ca615a9708e0d301281a87026f5c2067d17b16edf52cbf', 'A1', true, 'easy', 'firebase', 2, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "frase_055", "note_culturale": "Chiedere l''ora. ''In punto'' (IT) e ''tasan'' (FI) sono enfasi comuni che l''inglese omette (semplicemente ''o''clock'')."}', NULL),
    (165, '(Dialogo) A: "What time is it?" / B: "It''s three o''clock."', 'phrase', '104b55fa44b50f8d697ff9036969f4c032426f6dca2298c4b4360c3387b7aed0', 'A1', true, 'easy', 'firebase', 3, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "frase_055", "note_culturale": "Chiedere l''ora. ''In punto'' (IT) e ''tasan'' (FI) sono enfasi comuni che l''inglese omette (semplicemente ''o''clock'')."}', NULL),
    (166, '(Dialogo) A: "Vieni al cinema stasera?" / B: "No, scusa, sono stanco morto."', 'phrase', '6518a5d2ff3ef370952cb28cdfc37f1bd9c5d12b5a0a93fdb215932088e1d417', 'A1', true, 'easy', 'firebase', 1, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "frase_056", "note_culturale": "Rifiutare un invito a causa della stanchezza. ''Stanco morto'' (morte), ''ihan poikki'' (rotto) e ''dead tired'' (morte) sono le iperboli idiomatiche equivalenti."}', NULL),
    (167, '(Dialogo) A: "Tuletko elokuviin illalla?" / B: "Ei kiitos, olen ihan poikki."', 'phrase', '0011493fa397a310895c402099dd58869b0451c1ea32c68fb074bf4a048efd06', 'A1', true, 'easy', 'firebase', 2, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "frase_056", "note_culturale": "Rifiutare un invito a causa della stanchezza. ''Stanco morto'' (morte), ''ihan poikki'' (rotto) e ''dead tired'' (morte) sono le iperboli idiomatiche equivalenti."}', NULL),
    (168, '(Dialogo) A: "Are you coming to the movies tonight?" / B: "No thanks, I''m dead tired."', 'phrase', 'c368dedee1f136798f8e9b2d753b64e81fe090f89fa4fdb9dd88c635ef34c323', 'A1', true, 'easy', 'firebase', 3, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "frase_056", "note_culturale": "Rifiutare un invito a causa della stanchezza. ''Stanco morto'' (morte), ''ihan poikki'' (rotto) e ''dead tired'' (morte) sono le iperboli idiomatiche equivalenti."}', NULL),
    (169, '(Dialogo) A: "Mangiamo qualcosa?" / B: "Sì! Ho una fame da lupi!"', 'phrase', '1a7daa8b604a375fea776a83c42debd86bcee46f18f0548806ba59c72f855241', 'A1', true, 'easy', 'firebase', 1, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "frase_057", "note_culturale": "Esprime molta fame. L''italiano usa ''fame da lupi'' e il finlandese l''idioma composto ''sudennälkä'' (fame-da-lupo). L''inglese ''starving'' è l''equivalente naturale."}', NULL),
    (170, '(Dialogo) A: "Syödäänkö jotain?" / B: "Kyllä! Minulla on sudennälkä!"', 'phrase', 'd3a0afc5be4ee21a033f1d42da0000b7347ce1a84a1ab468cada53fe86ac812c', 'A1', true, 'easy', 'firebase', 2, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "frase_057", "note_culturale": "Esprime molta fame. L''italiano usa ''fame da lupi'' e il finlandese l''idioma composto ''sudennälkä'' (fame-da-lupo). L''inglese ''starving'' è l''equivalente naturale."}', NULL),
    (171, '(Dialogo) A: "Should we get something to eat?" / B: "Yes, I''m starving!"', 'phrase', 'd1f86ead2131adbf18a7f7d708b700678d44c1d8ca516f1724de18e0ace405e6', 'A1', true, 'easy', 'firebase', 3, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "frase_057", "note_culturale": "Esprime molta fame. L''italiano usa ''fame da lupi'' e il finlandese l''idioma composto ''sudennälkä'' (fame-da-lupo). L''inglese ''starving'' è l''equivalente naturale."}', NULL),
    (172, '(Dialogo) A: "Mamma mia, 30 gradi!" / B: "Che caldo! Prendo un''acqua."', 'phrase', '69fc789b1c7d0304f5b89fbb49696ef7d5fe8a6c5ae6d680ee72a1790ba8b857', 'A1', true, 'easy', 'firebase', 1, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "frase_058", "note_culturale": "Reazione naturale e standard alle alte temperature, seguita da un''azione."}', NULL),
    (173, '(Dialogo) A: "Oho, 30 astetta!" / B: "Onpa kuuma! Otan veden."', 'phrase', 'ea81c8eace2eb66f3d6b0de631974d5d01bc9b6d22947d52eb9af8c33ecf6bd2', 'A1', true, 'easy', 'firebase', 2, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "frase_058", "note_culturale": "Reazione naturale e standard alle alte temperature, seguita da un''azione."}', NULL),
    (174, '(Dialogo) A: "Wow, 30 degrees!" / B: "It''s so hot! I''ll get a water."', 'phrase', '9579a38496821803269030b9e0dfb0157f89ecf0031d97cf3ae342920e25e999', 'A1', true, 'easy', 'firebase', 3, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "frase_058", "note_culturale": "Reazione naturale e standard alle alte temperature, seguita da un''azione."}', NULL),
    (175, '(Dialogo) A: "Andiamo a fare una passeggiata?" / B: "Adesso? Si gela fuori!"', 'phrase', 'bd9faf96f921e6081fb63f6d48e518212ebdbb803a6ab21a9626ed2ad37b1165', 'A1', true, 'easy', 'firebase', 1, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "frase_059", "note_culturale": "Esprimere freddo intenso. ''Si gela'' / ''jääkylmä'' (freddo ghiaccio) / ''it''s freezing'' sono equivalenti."}', NULL),
    (176, '(Dialogo) A: "Mennäänkö kävelylle?" / B: "Nytkö? Siellä on jääkylmä!"', 'phrase', '27cee97d4e74523f6e3d20a9cc1704f5d6a141593137907d9e4f44166637c0dc', 'A1', true, 'easy', 'firebase', 2, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "frase_059", "note_culturale": "Esprimere freddo intenso. ''Si gela'' / ''jääkylmä'' (freddo ghiaccio) / ''it''s freezing'' sono equivalenti."}', NULL),
    (177, '(Dialogo) A: "Should we go for a walk?" / B: "Now? It''s freezing out there!"', 'phrase', '5ff4fd78260dc1ca7b315854d196fd932e2e8c120980ec835b29d7d576229ece', 'A1', true, 'easy', 'firebase', 3, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "frase_059", "note_culturale": "Esprimere freddo intenso. ''Si gela'' / ''jääkylmä'' (freddo ghiaccio) / ''it''s freezing'' sono equivalenti."}', NULL),
    (178, '(Dialogo) A: "Prendi un''altra birra?" / B: "No grazie, mi gira già la testa."', 'phrase', '861c02b5657c1e3b3dcd6cd2e8585b4882c9bcdd369166fe8bcf03fa98729cb4', 'A1', true, 'easy', 'firebase', 1, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "frase_060", "note_culturale": "Esprimere la sensazione di vertigine (es. da alcol). ''Mi gira la testa'' e ''minua huimaa'' (mi fa sentire le vertigini) sono gli equivalenti naturali."}', NULL),
    (179, '(Dialogo) A: "Otatko toisen oluen?" / B: "Ei kiitos, minua jo huimaa."', 'phrase', '26b8716db1fec878521267b4d482fa98c9543b459d49e16179f56a1d8d245928', 'A1', true, 'easy', 'firebase', 2, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "frase_060", "note_culturale": "Esprimere la sensazione di vertigine (es. da alcol). ''Mi gira la testa'' e ''minua huimaa'' (mi fa sentire le vertigini) sono gli equivalenti naturali."}', NULL),
    (180, '(Dialogo) A: "Want another beer?" / B: "No thanks, I''m already dizzy."', 'phrase', '6eb088eddeb24cb723abb819d80e0f2194e9c53f22daf29ed01544e37843fbcb', 'A1', true, 'easy', 'firebase', 3, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "frase_060", "note_culturale": "Esprimere la sensazione di vertigine (es. da alcol). ''Mi gira la testa'' e ''minua huimaa'' (mi fa sentire le vertigini) sono gli equivalenti naturali."}', NULL),
    (181, '(Dialogo) A: "Com''era la zuppa?" / B: "Buona, ma bruciava da morire!"', 'phrase', 'd77fae2e36635c88596b8e93ba86e282e1239bd697d65668ba66f677511ef4de', 'A1', true, 'easy', 'firebase', 1, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "frase_061", "note_culturale": "Iperbole per cibo molto caldo. ''Bruciava da morire'' / ''tulikuumaa'' (fuoco-caldo) / ''piping hot'' (idioma) sono gli equivalenti."}', NULL),
    (182, '(Dialogo) A: "Millaista keitto oli?" / B: "Hyvää, mutta se oli tulikuumaa!"', 'phrase', 'f84d33928315d934a30a2326829d206eef1541081c080b18583264a983d9e643', 'A1', true, 'easy', 'firebase', 2, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "frase_061", "note_culturale": "Iperbole per cibo molto caldo. ''Bruciava da morire'' / ''tulikuumaa'' (fuoco-caldo) / ''piping hot'' (idioma) sono gli equivalenti."}', NULL),
    (183, '(Dialogo) A: "How was the soup?" / B: "Good, but it was piping hot!"', 'phrase', 'b5cc9cf9e9a2429656319ee8798ee71086a7e4cc6dfc6ca9c6e6ee76f2c45b6e', 'A1', true, 'easy', 'firebase', 3, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "frase_061", "note_culturale": "Iperbole per cibo molto caldo. ''Bruciava da morire'' / ''tulikuumaa'' (fuoco-caldo) / ''piping hot'' (idioma) sono gli equivalenti."}', NULL),
    (184, '(Dialogo) A: "Che hai? Non stai bene?" / B: "No, mi sento poco bene."', 'phrase', '981f5ad22028cb42f52339273aec331ae677939f6b4838df3021ac04a8d44241', 'A1', true, 'easy', 'firebase', 1, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "frase_062", "note_culturale": "Modo generico per esprimere malessere."}', NULL),
    (185, '(Dialogo) A: "Mikä sinulla on? Voitko huonosti?" / B: "Kyllä, oloni on vähän huono."', 'phrase', '238510eaa518e58d8894d3befa0dfc865414abbca690da5e49a9a9060cc67a33', 'A1', true, 'easy', 'firebase', 2, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "frase_062", "note_culturale": "Modo generico per esprimere malessere."}', NULL),
    (186, '(Dialogo) A: "What''s wrong? Are you unwell?" / B: "Yes, I feel a bit sick."', 'phrase', '2fa6d9d81ee19b57078679c35da84e17c7e733487d5590db103f522207a47e47', 'A1', true, 'easy', 'firebase', 3, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "frase_062", "note_culturale": "Modo generico per esprimere malessere."}', NULL),
    (187, '(Dialogo) A: "Hai sete?" / B: "Sì, sto morendo di sete."', 'phrase', '2f2610fd06b5806d213386b843c54b7a9b7a312416f0f4e8bb391cc31f5afeb2', 'A1', true, 'easy', 'firebase', 1, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "frase_063", "note_culturale": "Iperbole comune per esprimere molta sete. Le tre lingue usano la metafora del ''morire'' (morire, kuolla, dying)."}', NULL),
    (188, '(Dialogo) A: "Onko sinulla jano?" / B: "Kyllä, olen kuolla janoon."', 'phrase', '52b5b3195d5a15c0dc710d13a8ebf4cda7a0d240f38aad12aed249fe9638ff4d', 'A1', true, 'easy', 'firebase', 2, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "frase_063", "note_culturale": "Iperbole comune per esprimere molta sete. Le tre lingue usano la metafora del ''morire'' (morire, kuolla, dying)."}', NULL),
    (189, '(Dialogo) A: "Are you thirsty?" / B: "Yes, I''m dying of thirst."', 'phrase', '213475095d8e652b93603073d5d3b37e6d7cff6a0f790ef09fa5f6f6c01e8640', 'A1', true, 'easy', 'firebase', 3, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "frase_063", "note_culturale": "Iperbole comune per esprimere molta sete. Le tre lingue usano la metafora del ''morire'' (morire, kuolla, dying)."}', NULL),
    (190, '(Dialogo) A: "Perché sbadigli?" / B: "Ho un sonno terribile."', 'phrase', '7d368ab5b6853a056a2c90763e0bb4af377f3e5a68caf991f6e4d56b87ff5cb2', 'A1', true, 'easy', 'firebase', 1, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "frase_064", "note_culturale": "Esprimere molta sonnolenza. L''italiano usa ''avere sonno'', il finlandese il verbo impersonale ''nukuttaa'' (mi fa sentire sonno)."}', NULL),
    (191, '(Dialogo) A: "Miksi haukottelet?" / B: "Minua nukuttaa kamalasti."', 'phrase', 'de71721f5161fb22c2b7e74668637f53affe9f85c6e19433c5c55095c49d096f', 'A1', true, 'easy', 'firebase', 2, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "frase_064", "note_culturale": "Esprimere molta sonnolenza. L''italiano usa ''avere sonno'', il finlandese il verbo impersonale ''nukuttaa'' (mi fa sentire sonno)."}', NULL),
    (192, '(Dialogo) A: "Why are you yawning?" / B: "I''m terribly sleepy."', 'phrase', '0b5a8a2a5578eba21856db06e547286ba1dbaa3ef12c19ce56feb946cb672e74', 'A1', true, 'easy', 'firebase', 3, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "frase_064", "note_culturale": "Esprimere molta sonnolenza. L''italiano usa ''avere sonno'', il finlandese il verbo impersonale ''nukuttaa'' (mi fa sentire sonno)."}', NULL),
