    (194, '(Dialogo) A: "Sinä täriset!" / B: "Kyllä, minulla on vilunväristyksiä."', 'phrase', 'f7aad84f76ba9e4b649817c5fadc5889e8c55c8a93c3eb2ab4c9648d91e548e3', 'A1', true, 'easy', 'firebase', 2, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "frase_065", "note_culturale": "Descrivere la sensazione di brividi (da freddo o febbre). ''Avere i brividi'' / ''I''ve got the chills'' (idioma) / ''minulla on vilunväristyksiä''."}', NULL),
    (195, '(Dialogo) A: "You''re shivering!" / B: "Yes, I''ve got the chills."', 'phrase', 'df9aa2192f7237367502d90012cd3021754d2b959b523f529baa9b8d1ad3181e', 'A1', true, 'easy', 'firebase', 3, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "frase_065", "note_culturale": "Descrivere la sensazione di brividi (da freddo o febbre). ''Avere i brividi'' / ''I''ve got the chills'' (idioma) / ''minulla on vilunväristyksiä''."}', NULL),
    (196, '(Dialogo) A: "Vuoi mangiare?" / B: "No, non ho fame."', 'phrase', '94ef9bdd3e9a61ccb8eea4aa05e7cf9e6b9f33b94a6efa37d520702ed7bfca95', 'A1', true, 'easy', 'firebase', 1, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "frase_066", "note_culturale": "Risposta negativa standard alla sensazione di fame."}', NULL),
