    (198, '(Dialogo) A: "Do you want to eat?" / B: "No, I''m not hungry."', 'phrase', '3c8e68d183944d29643ca5d5c5a9ec89be4b47e943db68483465b4f77fc7b49c', 'A1', true, 'easy', 'firebase', 3, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "frase_066", "note_culturale": "Risposta negativa standard alla sensazione di fame."}', NULL),
    (199, '(Dialogo) A: "Domani andiamo al lago." / B: "Che bello!"', 'phrase', '9415ca1354cfadf827cf5145828e80f2d806fef2f2c9e5905fd2350574a00529', 'A1', true, 'easy', 'firebase', 1, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "frase_067", "note_culturale": "Espressione esclamativa per apprezzamento o gioia semplice."}', NULL),
