    (215, '(Dialogo) A: "Mennäänkö syömään jäätelöä?" / B: "Loistava idea!"', 'phrase', 'd79a352de9f1b569020e0e6706ac303638f507998ba8b8ecf49ee30d372b37b0', 'A1', true, 'easy', 'firebase', 2, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "frase_072", "note_culturale": "Risposta positiva standard a una proposta."}', NULL),
    (216, '(Dialogo) A: "Should we go get ice cream?" / B: "Great idea!"', 'phrase', '028f9371a8ca2c17cd149add3b00431c9aaceee1411b830ea2b3508dff00542a', 'A1', true, 'easy', 'firebase', 3, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "frase_072", "note_culturale": "Risposta positiva standard a una proposta."}', NULL),
    (217, '(Dialogo) A: "Ho finito l''esame." / B: "E allora? Com''è andata?"', 'phrase', '8b7f7b070018659a4bdff8a1079bd2c33f2398f74accdb790bc439d0f7bb4c15', 'A1', true, 'easy', 'firebase', 1, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "frase_073", "note_culturale": "Modo colloquiale per chiedere l''esito. ''E allora?'' / ''No niin?'' / ''So?'' sono equivalenti per sollecitare una risposta."}', NULL),
    (218, '(Dialogo) A: "Sain kokeen tehtyä." / B: "No niin? Miten meni?"', 'phrase', 'bf97d51dca8fd1e095d5d4b15133c6fb3f30a7314a931c49b4b0bf5e8b13e397', 'A1', true, 'easy', 'firebase', 2, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "frase_073", "note_culturale": "Modo colloquiale per chiedere l''esito. ''E allora?'' / ''No niin?'' / ''So?'' sono equivalenti per sollecitare una risposta."}', NULL),
