    (221, '(Dialogo) A: "Vihdoinkin perjantai!" / B: "Onneksi!"', 'phrase', '2942c4c1e98698ef6089de92d53cef5976ddc2390f3824ffd3ba17eefbfa3ef5', 'A1', true, 'easy', 'firebase', 2, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "frase_074", "note_culturale": "Esprimere sollievo. ''Meno male!'' / ''Onneksi!'' (Per fortuna!) / ''Thank goodness!'' sono equivalenti."}', NULL),
    (222, '(Dialogo) A: "Finally Friday!" / B: "Thank goodness!"', 'phrase', '0a02982a5f0437aa234899ad10116f66b0bb0ab322b9cbe9516c3a9fd14b6bca', 'A1', true, 'easy', 'firebase', 3, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "frase_074", "note_culturale": "Esprimere sollievo. ''Meno male!'' / ''Onneksi!'' (Per fortuna!) / ''Thank goodness!'' sono equivalenti."}', NULL),
