    (230, '(Dialogo) A: "Olit tosi hyvä." / B: "Kiitos, liian ystävällistä."', 'phrase', 'd9b71b5561e8d7aa9f9c1a25701b0d1fb8ad4a6ac143bb11d39a71cf79149cb9', 'A1', true, 'easy', 'firebase', 2, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "frase_077", "note_culturale": "Modo umile di accettare un complimento. ''Troppo buono'' / ''liian ystävällistä'' / ''you''re too kind''."}', NULL),
    (231, '(Dialogo) A: "You were great." / B: "Thanks, you''re too kind."', 'phrase', '0d185b3bf651661a6439efed12e717b9f8f1929c4c8066f1bfb9fd4668c719f3', 'A1', true, 'easy', 'firebase', 3, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "frase_077", "note_culturale": "Modo umile di accettare un complimento. ''Troppo buono'' / ''liian ystävällistä'' / ''you''re too kind''."}', NULL),
