    (236, '(Dialogo) A: "Museo on kiinni tänään." / B: "Harmi."', 'phrase', '5fc5a6ce278d5db27dcafbb609de2f798502877de18c8365b756953c20cd123a', 'A1', true, 'easy', 'firebase', 2, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "frase_079", "note_culturale": "Esprime dispiacere per una piccola sfortuna. ''Che peccato'' / ''Harmi'' / ''What a pity''."}', NULL),
