    (285, '(Dialogo) A: "Let''s wait here." / B: "Yeah, it''s pouring."', 'phrase', 'db320179d8de9772c59e0ed0a4a191e3d17b744b6e781085db523de9fd6db55a', 'A2', true, 'easy', 'firebase', 3, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "frase_096", "note_culturale": ""}', NULL),
    (286, '(Dialogo) A: "Non respiro." / B: "Hai ragione, c''è un''afa terribile."', 'phrase', '713bc97e9f8604b1adf92d63276f1d59c22b6901c847c3d2280c840cf394df0e', 'A2', true, 'easy', 'firebase', 1, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "frase_097", "note_culturale": ""}', NULL),
    (287, '(Dialogo) A: "En saa henkeä." / B: "Olet oikeassa, on kamalan hiostava ilma."', 'phrase', 'ffd47977e3493f17d456b48d9139edf69e6b69f8871a284016a0e8d9b3a639e3', 'A2', true, 'easy', 'firebase', 2, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "frase_097", "note_culturale": ""}', NULL),
    (288, '(Dialogo) A: "I can''t breathe." / B: "You''re right, it''s terribly muggy."', 'phrase', 'c2b36f9b532640b261f83e2d46b1943cb3a16dc3d828272aa641ab7eccaa8104', 'A2', true, 'easy', 'firebase', 3, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "frase_097", "note_culturale": ""}', NULL),
    (289, '(Dialogo) A: "Che rumore è?" / B: "Grandina! Metti la macchina in garage!"', 'phrase', '6f6fb0fa581c7a070a4cb67c14fb2941491bd72f569cc5a5bed0faa584ee8eb8', 'A2', true, 'easy', 'firebase', 1, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "frase_098", "note_culturale": ""}', NULL),
    (290, '(Dialogo) A: "Mitä ääntä tuo on?" / B: "Sataa rakeita! Aja auto talliin!"', 'phrase', '8c7b325f77a845d49a1bcdca4027d69f609f58636f43508981d7639bdf1c2c60', 'A2', true, 'easy', 'firebase', 2, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "frase_098", "note_culturale": ""}', NULL),
    (291, '(Dialogo) A: "What''s that noise?" / B: "It''s hailing! Get the car in the garage!"', 'phrase', 'bcf27d3eb323cbbadba460010c4add4acd5487e0dcc7e5e32c83c95146c59312', 'A2', true, 'easy', 'firebase', 3, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "frase_098", "note_culturale": ""}', NULL),
    (292, '(Dialogo) A: "Non si vede niente." / B: "Eh, c''è una nebbia fittissima."', 'phrase', '7505213d9c2ed6a0006acae3f9d8671036832c0795dfed793ce07f8bc84de8e3', 'A2', true, 'easy', 'firebase', 1, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "frase_099", "note_culturale": ""}', NULL),
    (293, '(Dialogo) A: "Ei näy mitään." / B: "Jep, on tosi paksu sumu."', 'phrase', 'faf2de77452f53db7212049f610a1f84372c3e8154f47b07f064aa400c240c86', 'A2', true, 'easy', 'firebase', 2, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "frase_099", "note_culturale": ""}', NULL),
    (294, '(Dialogo) A: "I can''t see anything." / B: "Yeah, there''s a really thick fog."', 'phrase', '967b038fe61813a5855b5c95bd0c95c583820f3714cd04b420bb3eaccf2ff47c', 'A2', true, 'easy', 'firebase', 3, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "frase_099", "note_culturale": ""}', NULL),
    (295, '(Dialogo) A: "Sono un po'' nervoso per l''esame." / B: "Non ti preoccupare, andrà benissimo!"', 'phrase', '4bc40b8d9cb50c144a5611635b0f2afe6e7c7cb9532952fb3af0fa1bcbd07c98', 'A2', true, 'easy', 'firebase', 1, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "frase_100", "note_culturale": ""}', NULL),
    (296, '(Dialogo) A: "Minua vähän jännittää se koe." / B: "Älä huoli, se menee tosi hyvin!"', 'phrase', '2483725f465641a97dfe96be7d411f8f2e44b9cc624904407bad9eef886069eb', 'A2', true, 'easy', 'firebase', 2, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "frase_100", "note_culturale": ""}', NULL),
    (297, '(Dialogo) A: "I''m a bit nervous about the exam." / B: "Don''t worry, you''ll do great!"', 'phrase', '8f1da7394b7d8d7c7a1939098c4f708071fae1fa64b20d2dfb8a373cb6d3c8ed', 'A2', true, 'easy', 'firebase', 3, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "frase_100", "note_culturale": ""}', NULL),
    (298, '(Dialogo) A: "Grazie per l''aiuto." / B: "Ci mancherebbe! Per gli amici questo e altro."', 'phrase', 'd86a54904db0843ba1533d99d4ba1530db48e6a0ee0fd41082ab108393dcdf5f', 'A2', true, 'easy', 'firebase', 1, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "frase_101", "note_culturale": ""}', NULL),
    (299, '(Dialogo) A: "Kiitos avusta." / B: "Ei kestä! Ystävien vuoksi mitä vain."', 'phrase', '6fefbb74d3fbc9cd8786ad1722a25d21944b1e3cd3c6e7590a5aafdc229a6f26', 'A2', true, 'easy', 'firebase', 2, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "frase_101", "note_culturale": ""}', NULL),
    (300, '(Dialogo) A: "Thanks for the help." / B: "Don''t mention it! That''s what friends are for."', 'phrase', 'e4298d91af525817cfb07b99aa52d70b70133cec16e5b6bd5f32dc1a933d306f', 'A2', true, 'easy', 'firebase', 3, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "frase_101", "note_culturale": ""}', NULL),
    (301, '(Dialogo) A: "Ho litigato con mia sorella." / B: "Davvero? Mi dispiace tanto."', 'phrase', '92440146dfdd7a728aad67170af9a212aa9248392d23a6caa25fac03e5119365', 'A2', true, 'easy', 'firebase', 1, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "frase_102", "note_culturale": ""}', NULL),
    (302, '(Dialogo) A: "Riitelin siskoni kanssa." / B: "Ihanko totta? Olen tosi pahoillani."', 'phrase', '2c54e7c4a29455d9c5e982143d88d2c3f175c4da384d0673d236552d946ab939', 'A2', true, 'easy', 'firebase', 2, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "frase_102", "note_culturale": ""}', NULL),
    (303, '(Dialogo) A: "I had a fight with my sister." / B: "Really? I''m so sorry to hear that."', 'phrase', 'aff6e5a146e6bd105056c993f94b785da3fd85bc00349da83316e6bc08440d20', 'A2', true, 'easy', 'firebase', 3, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "frase_102", "note_culturale": ""}', NULL),
    (304, '(Dialogo) A: "Cosa pensi di Marco?" / B: "Onestamente? Non lo sopporto."', 'phrase', '115b0bf37874ca1198175c56152b79fc21a46d98f4ab8b597e455f6f42305c69', 'A2', true, 'easy', 'firebase', 1, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "frase_103", "note_culturale": ""}', NULL),
    (305, '(Dialogo) A: "Mitä mieltä olet Marcosta?" / B: "Rehellisesti? En voi sietää häntä."', 'phrase', '4ae9b55612e8ad6ef5dcd9a0e91403a5bac15742fd1c29c2a504a97927b6c2fb', 'A2', true, 'easy', 'firebase', 2, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "frase_103", "note_culturale": ""}', NULL),
    (306, '(Dialogo) A: "What do you think of Marco?" / B: "Honestly? I can''t stand him."', 'phrase', 'c48a02f46447d668c425c9bdc443a5b5ad4016bd765989da70dc75a847da8788', 'A2', true, 'easy', 'firebase', 3, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "frase_103", "note_culturale": ""}', NULL),
    (307, '(Dialogo) A: "Luca mi ha detto una bugia." / B: "Ma dai! Non me l''aspettavo."', 'phrase', '1ba53a319469bd60b99891a114a73f4cdf6ff6184b66d3eb60994dec37fa4c54', 'A2', true, 'easy', 'firebase', 1, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "frase_104", "note_culturale": ""}', NULL),
    (308, '(Dialogo) A: "Luca valehteli minulle." / B: "Ei ole totta! Sitä en olisi odottanut."', 'phrase', '7e5abd17e5d1e513662de9dca51894b52a13b6cce1f7d51c7219c694f2ab5900', 'A2', true, 'easy', 'firebase', 2, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "frase_104", "note_culturale": ""}', NULL),
    (309, '(Dialogo) A: "Luca told me a lie." / B: "No way! I didn''t expect that."', 'phrase', '35ee81b7e04ebcd570794be5a1f7975e43d12d61a461099779b9e7945542a990', 'A2', true, 'easy', 'firebase', 3, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "frase_104", "note_culturale": ""}', NULL),
    (310, '(Dialogo) A: "Sei arrabbiato con me?" / B: "No, tranquillo, tutto a posto."', 'phrase', '04dc5a087411d0860c98210d0b4ec539cfae5051ad0918b74dbad9fd43df3a74', 'A2', true, 'easy', 'firebase', 1, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "frase_105", "note_culturale": ""}', NULL),
    (311, '(Dialogo) A: "Oletko vihainen minulle?" / B: "Ei, rauhassa, kaikki on kunnossa."', 'phrase', 'e7dec270869b7c556f64870c80ff21e9fa09a7c52d4a6af140a8a6ed621f3794', 'A2', true, 'easy', 'firebase', 2, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "frase_105", "note_culturale": ""}', NULL),
    (312, '(Dialogo) A: "Are you angry with me?" / B: "No, don''t worry, we''re cool."', 'phrase', '1f5f798808efb0ee18be656d6530d706a37bbcbd1ce33b31b58bd92338dc058a', 'A2', true, 'easy', 'firebase', 3, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "frase_105", "note_culturale": ""}', NULL),
    (313, '(Dialogo) A: "Mi serve un consiglio." / B: "Dimmi tutto."', 'phrase', 'd6bf1197bd99162767dd42b4834c67c7d6380872a09b9eaaff7c079d2b3392c5', 'A2', true, 'easy', 'firebase', 1, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "frase_106", "note_culturale": ""}', NULL),
    (314, '(Dialogo) A: "Tarvitsen neuvon." / B: "Kerro pois."', 'phrase', 'd2ea5622779e660a98e3f05f48cf510e927a5ee575ca93203d431b33b009ac03', 'A2', true, 'easy', 'firebase', 2, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "frase_106", "note_culturale": ""}', NULL),
    (315, '(Dialogo) A: "I need some advice." / B: "I''m all ears."', 'phrase', '0eff9d28057e1f7fad6acab7c9a1570ef9e5473dbabd0ca33eced9bca9ab37fe', 'A2', true, 'easy', 'firebase', 3, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "frase_106", "note_culturale": ""}', NULL),
    (316, '(Dialogo) A: "Non vedo l''ora di partire!" / B: "Beato te! Io devo lavorare."', 'phrase', '5c40d34361ba81a4c8e8c0b274f3b9c6ac1278b90b53c2c8943f8ba85cff77da', 'A2', true, 'easy', 'firebase', 1, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "frase_107", "note_culturale": ""}', NULL),
    (317, '(Dialogo) A: "Odotan innolla lähtöä!" / B: "Onnekas! Minun täytyy tehdä töitä."', 'phrase', '31c06d797cc566619cb38e4829d092b99249879f4756c0e80402359c7cab9ec2', 'A2', true, 'easy', 'firebase', 2, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "frase_107", "note_culturale": ""}', NULL),
    (318, '(Dialogo) A: "I can''t wait to leave!" / B: "Lucky you! I have to work."', 'phrase', 'f2b171947b176c058cd3c3480d3b34315e522901c1d868050040245d1e7e69eb', 'A2', true, 'easy', 'firebase', 3, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "frase_107", "note_culturale": ""}', NULL),
    (319, '(Dialogo) A: "Hai sempre ragione tu!" / B: "Ma va là! Non è vero."', 'phrase', '3b1baee307207fbc8754afc156fc628c38c805d38a64905e3a101a398003a3c3', 'A2', true, 'easy', 'firebase', 1, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "frase_108", "note_culturale": ""}', NULL),
    (320, '(Dialogo) A: "Olet aina oikeassa!" / B: "Älä viitsi! Ei ole totta."', 'phrase', '9a7a5f860a511813d6160f83e2d5946ac46c8f2fbdebd5089a6c50b0e543aeba', 'A2', true, 'easy', 'firebase', 2, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "frase_108", "note_culturale": ""}', NULL),
    (321, '(Dialogo) A: "You''re always right!" / B: "Come on! That''s not true."', 'phrase', 'dd2d9ae7e907edd8df2fbd5187ecc5cba83f5ea591b7f846b196815c5e624afe', 'A2', true, 'easy', 'firebase', 3, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "frase_108", "note_culturale": ""}', NULL),
    (322, '(Dialogo) A: "Prometti di non dirlo a nessuno?" / B: "Sì, acqua in bocca!"', 'phrase', '7f926afa5cf2cc42a9e58f680fc930819659f0d8434c7628b651a5b2e68f7fb8', 'A2', true, 'easy', 'firebase', 1, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "frase_109", "note_culturale": ""}', NULL),
    (323, '(Dialogo) A: "Lupaatko, ettet kerro kenellekään?" / B: "Joo, pidän suuni kiinni."', 'phrase', 'cc5cfbc23440158932f54bec98267479be59ca6300f5b9a75b722cce13520d5a', 'A2', true, 'easy', 'firebase', 2, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "frase_109", "note_culturale": ""}', NULL),
    (324, '(Dialogo) A: "Promise you won''t tell anyone?" / B: "Yes, my lips are sealed!"', 'phrase', '6c32c85739ca811cb5a06822240144e6a2e277c3ccaff671b084165fd4f092e4', 'A2', true, 'easy', 'firebase', 3, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "frase_109", "note_culturale": ""}', NULL),
    (325, '(Dialogo) A: "Posso fidarmi di te?" / B: "Certo, al cento per cento."', 'phrase', '81c13322759e5e6f6827741e470d1cfa7516a658c0a77a2c490aad3e54766f0c', 'A2', true, 'easy', 'firebase', 1, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "frase_110", "note_culturale": ""}', NULL),
    (326, '(Dialogo) A: "Voinko luottaa sinuun?" / B: "Totta kai, sataprosenttisesti."', 'phrase', 'ff00d44c61ce4103dfffe66574edde826dc664aff2ec0a255b46bf9e2f34cd6d', 'A2', true, 'easy', 'firebase', 2, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "frase_110", "note_culturale": ""}', NULL),
    (327, '(Dialogo) A: "Can I trust you?" / B: "Of course, one hundred percent."', 'phrase', '9d2dbd551ec4848165b9c2c2232e571ec9c9591848e5a3a06ec0f9e81927d2f7', 'A2', true, 'easy', 'firebase', 3, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "frase_110", "note_culturale": ""}', NULL),
    (328, '(Dialogo) A: "Stai scherzando, vero?" / B: "No, sono serissimo."', 'phrase', '6f548fdbe70d6198d74470c98d1249e8a8313bfc0b05ea1dc1d40afa7b33b209', 'A2', true, 'easy', 'firebase', 1, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "frase_111", "note_culturale": ""}', NULL),
    (329, '(Dialogo) A: "Vitsailethan, vai mitä?" / B: "En, olen aivan tosissani."', 'phrase', '700ec78cea44287dfcf56c1feb0bf99df6e07cdab7c4a409b49946eafac64322', 'A2', true, 'easy', 'firebase', 2, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "frase_111", "note_culturale": ""}', NULL),
    (330, '(Dialogo) A: "You''re kidding, right?" / B: "No, I''m dead serious."', 'phrase', '26fd9ac0f3f0b7e969c289f8a0adf795c8708b7fc6f25143a4d5f6bb61ee3c65', 'A2', true, 'easy', 'firebase', 3, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "frase_111", "note_culturale": ""}', NULL),
    (331, '(Dialogo) A: "Com''è andato l''esame di storia?" / B: "Uno schifo. Penso di essere bocciato."', 'phrase', '603873dfbd7338315d061d49e4d51dfaad02ab2d5667ed3873fa4cd8383a6a43', 'A2', true, 'easy', 'firebase', 1, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "frase_112", "note_culturale": ""}', NULL),
    (332, '(Dialogo) A: "Miten historian koe meni?" / B: "Ihan surkeasti. Luulen, että en pääse läpi."', 'phrase', '57cc449a822e73c4933b6afe9dfc609e8b3dcb5fa600a4727d4bae4016ba70f7', 'A2', true, 'easy', 'firebase', 2, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "frase_112", "note_culturale": ""}', NULL),
    (333, '(Dialogo) A: "How did the history exam go?" / B: "Terrible. I think I failed."', 'phrase', '8a9470bdc3969741d579b9223711607c841e21a2fa62e3129cb5d444649fe2e7', 'A2', true, 'easy', 'firebase', 3, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "frase_112", "note_culturale": ""}', NULL),
    (334, '(Dialogo) A: "Hai studiato per la verifica?" / B: "Sì, ho passato tutto il weekend sui libri."', 'phrase', 'bf925d0536ad5a310f7b808ef14142d2dda619c8a3d574986371ede9bd77d77a', 'A2', true, 'easy', 'firebase', 1, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "frase_113", "note_culturale": ""}', NULL),
    (335, '(Dialogo) A: "Oletko lukenut kokeeseen?" / B: "Joo, vietin koko viikonlopun kirjojen parissa."', 'phrase', '1feaf37b60f588f6f428d834032b7524eb9ff543b85ca700f0a6838cbd620109', 'A2', true, 'easy', 'firebase', 2, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "frase_113", "note_culturale": ""}', NULL),
    (336, '(Dialogo) A: "Did you study for the test?" / B: "Yeah, I spent all weekend hitting the books."', 'phrase', '6df52b6f9e0812d4407f9edfa1131be0ee7cb3426bb7be52df22bfa12fce2d36', 'A2', true, 'easy', 'firebase', 3, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "frase_113", "note_culturale": ""}', NULL),
    (337, '(Dialogo) A: "Oggi ho preso 10 in matematica!" / B: "Tanta roba! Complimenti!"', 'phrase', '786bfcfcccc29d1bb3fd39876053f4ede004ecb100e53ff2f8606c644bb8b041', 'A2', true, 'easy', 'firebase', 1, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "frase_114", "note_culturale": ""}', NULL),
    (338, '(Dialogo) A: "Sain tänään matematiikasta kympin!" / B: "Mahtavaa! Onneksi olkoon!"', 'phrase', '681202a8b2bf5f715b2bc7c8231ac2a3f3e0c2196c5e1d12bdda732c78264350', 'A2', true, 'easy', 'firebase', 2, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "frase_114", "note_culturale": ""}', NULL),
    (339, '(Dialogo) A: "I got a 10 in math today!" / B: "Awesome! Congratulations!"', 'phrase', 'ecb7f011ed0ff437a2b090f69bad7dfe1b8b3669f20f3d636f0c8ae64f8b8a64', 'A2', true, 'easy', 'firebase', 3, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "frase_114", "note_culturale": ""}', NULL),
    (340, '(Dialogo) A: "Usciamo?" / B: "Non posso, devo fare i compiti."', 'phrase', 'b113660aad841b1c6007237a4f1447257c0eb156e1ce22e2631a496f16ee693e', 'A2', true, 'easy', 'firebase', 1, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "frase_115", "note_culturale": ""}', NULL),
    (341, '(Dialogo) A: "Lähdetäänkö ulos?" / B: "En voi, minun täytyy tehdä läksyt."', 'phrase', '0efd602a3c79c8ed7bad09cfaa133971f8d5b6b4a660d2550955c2381c066285', 'A2', true, 'easy', 'firebase', 2, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "frase_115", "note_culturale": ""}', NULL),
    (342, '(Dialogo) A: "Want to go out?" / B: "I can''t, I have to do my homework."', 'phrase', 'd05e6e16264cf2fc230b5c12a47250cc288915594b9770a853ded3335b897ea6', 'A2', true, 'easy', 'firebase', 3, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "frase_115", "note_culturale": ""}', NULL),
    (343, '(Dialogo) A: "Oggi hai lezione?" / B: "No, ho un''ora buca. Andiamo al bar?"', 'phrase', '5fc373bdeed3dee16b900014d437ad3f4a4e65628942dc6ff801f58d1d135951', 'A2', true, 'easy', 'firebase', 1, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "frase_116", "note_culturale": ""}', NULL),
    (344, '(Dialogo) A: "Onko sinulla tänään oppituntia?" / B: "Ei, minulla on hyppytunti. Mennäänkö kahvilaan?"', 'phrase', 'fae2e2c796ad9386d2ab72332bc55775f1f936671e5d4cad2d62fc0a5c3d6556', 'A2', true, 'easy', 'firebase', 2, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "frase_116", "note_culturale": ""}', NULL),
    (345, '(Dialogo) A: "Do you have class today?" / B: "No, I have a free period. Want to go to the café?"', 'phrase', 'b2105cdc08218a20b24cc630f121ff2400b75d26341d38265ce925f674af7b32', 'A2', true, 'easy', 'firebase', 3, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "frase_116", "note_culturale": ""}', NULL),
    (346, '(Dialogo) A: "Hai capito la lezione?" / B: "Non ci ho capito niente."', 'phrase', '4575b1f31e443121b1a800a0eaf9aa38ff10831c74e13b61f28b1d147504efb6', 'A2', true, 'easy', 'firebase', 1, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "frase_117", "note_culturale": ""}', NULL),
    (347, '(Dialogo) A: "Ymmärsitkö oppitunnin?" / B: "En ymmärtänyt yhtään mitään."', 'phrase', '88b55f021f9d8586302c70e8f4a1a8ad13b451f5b11cddd6b27e4d5c94a69e0a', 'A2', true, 'easy', 'firebase', 2, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "frase_117", "note_culturale": ""}', NULL),
    (348, '(Dialogo) A: "Did you understand the lesson?" / B: "I didn''t understand a thing."', 'phrase', '5f54e48108f99b6ee07497aeda904b64854b328bef64bbe24a14b0e859c9adf1', 'A2', true, 'easy', 'firebase', 3, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "frase_117", "note_culturale": ""}', NULL),
    (349, '(Dialogo) A: "Il prof di fisica è severo." / B: "Lo so, è un osso duro."', 'phrase', 'ce17d0d9202a7e1252d72599cdf72a6a8c9ab5c075bfa75c4411c04dce290f44', 'A2', true, 'easy', 'firebase', 1, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "frase_118", "note_culturale": ""}', NULL),
    (350, '(Dialogo) A: "Fysiikan opettaja on ankara." / B: "Tiedän, hän on kova pala."', 'phrase', 'ed9efb0ceff59db2d2b99ab01f0d3362dd3707a2d07583a8f3333dd3a0af9c51', 'A2', true, 'easy', 'firebase', 2, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "frase_118", "note_culturale": ""}', NULL),
    (351, '(Dialogo) A: "The physics teacher is strict." / B: "I know, he''s a tough nut to crack."', 'phrase', '7577065b91c7947d03ef26a388698138426ad24811bd806b4f3c9ddfd86c92f8', 'A2', true, 'easy', 'firebase', 3, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "frase_118", "note_culturale": ""}', NULL),
    (352, '(Dialogo) A: "Perché sei così stanco?" / B: "Ho fatto le ore piccole per studiare."', 'phrase', '7faae2e0d5df91c573d743e042ad63484d08439f2d510873e14fd6e47d2e2fea', 'A2', true, 'easy', 'firebase', 1, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "frase_119", "note_culturale": ""}', NULL),
    (353, '(Dialogo) A: "Miksi olet niin väsynyt?" / B: "Kukkuin pikkutunneille opiskelemassa."', 'phrase', 'bfd2652740d8e6ab8ee5555965bb8dade77e8cb3116db05b6e034d00adf4d866', 'A2', true, 'easy', 'firebase', 2, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "frase_119", "note_culturale": ""}', NULL),
    (354, '(Dialogo) A: "Why are you so tired?" / B: "I stayed up late studying."', 'phrase', '5873eecc7914aa38afe1ec39e98d65be8d1e0ff8a285ef92d307145f6da6071c', 'A2', true, 'easy', 'firebase', 3, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "frase_119", "note_culturale": ""}', NULL),
    (355, '(Dialogo) A: "Domani abbiamo un test." / B: "Davvero? Allora devo ripassare."', 'phrase', '4046040c115e8be616b44f652ff48d402d6b3aa69b1410b07a6d82bf6278ccaf', 'A2', true, 'easy', 'firebase', 1, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "frase_120", "note_culturale": ""}', NULL),
    (356, '(Dialogo) A: "Huomenna meillä on koe." / B: "Ihanko totta? Sitten minun täytyy kerrata."', 'phrase', 'a3445c1d251b44997dcbbd9dd6cb7bffc4ebc55b2803590029e82b8cbe0d397e', 'A2', true, 'easy', 'firebase', 2, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "frase_120", "note_culturale": ""}', NULL),
    (357, '(Dialogo) A: "We have a test tomorrow." / B: "Really? Then I have to review."', 'phrase', '96d708461c11a30ad57c3650339cc9f5fc3b588d5c116c934356cb6d3efb1284', 'A2', true, 'easy', 'firebase', 3, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "frase_120", "note_culturale": ""}', NULL),
    (358, '(Dialogo) A: "Andiamo a scuola insieme?" / B: "Ok, ci vediamo alla stessa ora."', 'phrase', '3a60c526b934b84179b515b74b4fb234a12b7d8c4194ae6bf2b8929ce8691c00', 'A2', true, 'easy', 'firebase', 1, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "frase_121", "note_culturale": ""}', NULL),
    (359, '(Dialogo) A: "Mennäänkö kouluun yhdessä?" / B: "Ok, nähdään samaan aikaan."', 'phrase', 'd18ad9996bacd387491588720ce93b8162ac38f2209058bb8b6796837282aea8', 'A2', true, 'easy', 'firebase', 2, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "frase_121", "note_culturale": ""}', NULL),
    (360, '(Dialogo) A: "Should we go to school together?" / B: "Okay, see you at the same time."', 'phrase', '4baab68fd303a4f39874a7f05d166ac36bfaab109a46a3563a1b90d24004e0c2', 'A2', true, 'easy', 'firebase', 3, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "frase_121", "note_culturale": ""}', NULL),
    (361, '(Dialogo) A: "Hai sentito? Marco ha preso 4..." / B: "Poveraccio... era difficile?"', 'phrase', 'ebe3c3257fcd18322561879ece6387fd692ac5b5b2d76863ff589efd604b46d6', 'A2', true, 'easy', 'firebase', 1, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "frase_122", "note_culturale": ""}', NULL),
    (362, '(Dialogo) A: "Kuulitko? Marco sai nelosen..." / B: "Voi raukkaa... Oliko se vaikea?"', 'phrase', '5739b60cb6f0dd0d677b91cbeb621bdff74447ff9dd9e255eef75b9358b2a7e0', 'A2', true, 'easy', 'firebase', 2, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "frase_122", "note_culturale": ""}', NULL),
    (363, '(Dialogo) A: "Did you hear? Marco got a 4..." / B: "Poor guy... was it difficult?"', 'phrase', 'd90927f110f1fd20ad0cbc676d397e9c6590d9b9c1b4db7e322be001bc82239b', 'A2', true, 'easy', 'firebase', 3, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "frase_122", "note_culturale": ""}', NULL),
    (364, '(Dialogo) A: "Vieni alla festa stasera?" / B: "Non posso, sono al verde."', 'phrase', '273797292beabdd8bb5be0b7f71f437ee8a8f6b74cbeb64b1fb8db8156b05f71', 'A2', true, 'easy', 'firebase', 1, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "frase_123", "note_culturale": ""}', NULL),
    (365, '(Dialogo) A: "Tuletko juhliin illalla?" / B: "En voi, olen ihan rahaton."', 'phrase', 'ef41bacc972bedb220c6f0d851b044782e563060beddcfdcc6017cb48c4ddb4c', 'A2', true, 'easy', 'firebase', 2, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "frase_123", "note_culturale": ""}', NULL),
    (366, '(Dialogo) A: "Are you coming to the party tonight?" / B: "I can''t, I''m broke."', 'phrase', '315b7f5cbe57419573eb54cbe362e08c59bcb3cdd45f96f9ca654f56982cbfb2', 'A2', true, 'easy', 'firebase', 3, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "frase_123", "note_culturale": ""}', NULL),
    (367, '(Dialogo) A: "Quanto hai pagato quel cappotto?" / B: "Tantissimo, mi è costato un occhio della testa!"', 'phrase', '489d552b9cd660e3cbd8589c39d10b3efce6397ae0ddcdb28b32a771c3fdfd41', 'A2', true, 'easy', 'firebase', 1, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "frase_124", "note_culturale": ""}', NULL),
    (368, '(Dialogo) A: "Paljonko maksoit siitä takista?" / B: "Tosi paljon, se maksoi maltaita!"', 'phrase', '474af9ea5612285f7d7e7ac4ffc9468325ae8fd661f2a229e071ab23969d2b35', 'A2', true, 'easy', 'firebase', 2, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "frase_124", "note_culturale": ""}', NULL),
    (369, '(Dialogo) A: "How much did you pay for that coat?" / B: "A lot, it cost me an arm and a leg!"', 'phrase', 'd2b122bc3dede0f000c61540c41aa8f68af0bc32d670a110636d32f6ac8388d3', 'A2', true, 'easy', 'firebase', 3, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "frase_124", "note_culturale": ""}', NULL),
    (370, '(Dialogo) A: "Wow, che bel ristorante." / B: "Sì, ma è troppo caro per me."', 'phrase', '7135ecc69d8e798026155102da216c078263193b5681f9f440682dbf52315ce9', 'A2', true, 'easy', 'firebase', 1, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "frase_125", "note_culturale": ""}', NULL),
    (371, '(Dialogo) A: "Vau, mikä hieno ravintola." / B: "Joo, mutta se on liian kallis minulle."', 'phrase', 'feaa8e7a439c1ad02003205aa77b0f1b667b41dc59f473f566bdf756bbde6f22', 'A2', true, 'easy', 'firebase', 2, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "frase_125", "note_culturale": ""}', NULL),
    (372, '(Dialogo) A: "Wow, what a nice restaurant." / B: "Yeah, but it''s too expensive for me."', 'phrase', 'd17d0c611b1a2e5cf5b49f36b9826450c58861a6d7206108f429f1f3959c5a79', 'A2', true, 'easy', 'firebase', 3, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "frase_125", "note_culturale": ""}', NULL),
    (373, '(Dialogo) A: "Hai già comprato un''altra borsa?" / B: "Lo so... ho le mani bucate!"', 'phrase', '03707d291829dc445f04480a26983369e6ca3807c0c73ed671d8c70968805c49', 'A2', true, 'easy', 'firebase', 1, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "frase_126", "note_culturale": "Idiomi per ''spendere troppo facilmente''. ''Avere le mani bucate'' (IT), ''raha polttaa taskussa'' (FI, i soldi bruciano in tasca), ''burn through money'' (EN)."}', NULL),
    (374, '(Dialogo) A: "Ostitko taas uuden laukun?" / B: "Tiedän... raha polttaa taskussani!"', 'phrase', '236f63d9f9a8e7b175dc07c295b774120dc3e4a75a410efbefb6d20138e3ead3', 'A2', true, 'easy', 'firebase', 2, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "frase_126", "note_culturale": "Idiomi per ''spendere troppo facilmente''. ''Avere le mani bucate'' (IT), ''raha polttaa taskussa'' (FI, i soldi bruciano in tasca), ''burn through money'' (EN)."}', NULL),
    (375, '(Dialogo) A: "You bought another bag already?" / B: "I know... I just burn through money!"', 'phrase', '3c44b1d30a72f95791cd7fff31edeeb6cc24778f741c5693d9bf362a7d10a0e9', 'A2', true, 'easy', 'firebase', 3, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "frase_126", "note_culturale": "Idiomi per ''spendere troppo facilmente''. ''Avere le mani bucate'' (IT), ''raha polttaa taskussa'' (FI, i soldi bruciano in tasca), ''burn through money'' (EN)."}', NULL),
    (376, '(Dialogo) A: "Scusi, posso pagare?" / B: "Certo. Sono 10 euro."', 'phrase', '7b79e63639eba602d563ff585c6f4066db8404e50201a99271cecc8f809cc1fa', 'A2', true, 'easy', 'firebase', 1, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "frase_127", "note_culturale": "Dialogo standard per pagare."}', NULL),
    (377, '(Dialogo) A: "Anteeksi, voinko maksaa?" / B: "Toki. Se tekee 10 euroa."', 'phrase', '7df53f8d66e6416f3729f9312ce9478d7af9466c4b763e7cde222655f2afa910', 'A2', true, 'easy', 'firebase', 2, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "frase_127", "note_culturale": "Dialogo standard per pagare."}', NULL),
    (378, '(Dialogo) A: "Excuse me, can I pay?" / B: "Of course. That''s 10 euros."', 'phrase', 'ab08baa96e5df0803bfe2aea7e1b42686f1ebcb513ecc26fb1d5f26718637d78', 'A2', true, 'easy', 'firebase', 3, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "frase_127", "note_culturale": "Dialogo standard per pagare."}', NULL),
    (379, '(Dialogo) A: "Hai visto il prezzo?" / B: "Sì, è un vero affare!"', 'phrase', '26fd3da55b677274735ccf8d2e56eed9d09845dc2db6debd5fdc0187f8650832', 'A2', true, 'easy', 'firebase', 1, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "frase_128", "note_culturale": "Esprimere che qualcosa è a buon prezzo. ''Un affare'' (IT), ''todellinen löytö'' (FI, una vera scoperta), ''a real bargain'' (EN)."}', NULL),
    (380, '(Dialogo) A: "Näitkö hinnan?" / B: "Joo, se on todellinen löytö!"', 'phrase', 'de68337e5e8cf6c696b00dc0a510de0ffea008d9d0cb5db23841cc627f70720d', 'A2', true, 'easy', 'firebase', 2, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "frase_128", "note_culturale": "Esprimere che qualcosa è a buon prezzo. ''Un affare'' (IT), ''todellinen löytö'' (FI, una vera scoperta), ''a real bargain'' (EN)."}', NULL),
    (381, '(Dialogo) A: "Did you see the price?" / B: "Yeah, it''s a real bargain!"', 'phrase', '01f5eb31dddcbd661217f7fc46512d57b7f899fe65db8fb4ddb709eaf6add413', 'A2', true, 'easy', 'firebase', 3, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "frase_128", "note_culturale": "Esprimere che qualcosa è a buon prezzo. ''Un affare'' (IT), ''todellinen löytö'' (FI, una vera scoperta), ''a real bargain'' (EN)."}', NULL),
    (382, '(Dialogo) A: "Mi presti 20 euro?" / B: "Ok, ma me li rendi domani."', 'phrase', '503222ba6aedb2685982dc21dded5c499b34cace26777ecee183df353a4f6944', 'A2', true, 'easy', 'firebase', 1, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "frase_129", "note_culturale": "Chiedere un prestito e la condizione per la restituzione (''rendere'' / ''maksaa takaisin'' / ''pay back'')."}', NULL),
    (383, '(Dialogo) A: "Lainaatko minulle 20 euroa?" / B: "Ok, mutta maksat takaisin huomenna."', 'phrase', 'e7ecfeddea6c510a05e0bf34f730e3a60496fe92525c493d6f886401b8b879f0', 'A2', true, 'easy', 'firebase', 2, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "frase_129", "note_culturale": "Chiedere un prestito e la condizione per la restituzione (''rendere'' / ''maksaa takaisin'' / ''pay back'')."}', NULL),
    (384, '(Dialogo) A: "Can you lend me 20 euros?" / B: "Okay, but you pay me back tomorrow."', 'phrase', 'f58cfed0095d91fbdb9a2a80d22f7be17012bde592b2646e5047c4ba417553ed', 'A2', true, 'easy', 'firebase', 3, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "frase_129", "note_culturale": "Chiedere un prestito e la condizione per la restituzione (''rendere'' / ''maksaa takaisin'' / ''pay back'')."}', NULL),
    (385, '(Dialogo) A: "Questo maglione è in saldo?" / B: "Sì, è al 50% di sconto."', 'phrase', '67dd56c3e769966a6ca97282c44db9d1ba01835cb0012ce8e27bd5cd73ffe8c5', 'A2', true, 'easy', 'firebase', 1, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "frase_130", "note_culturale": "Dialogo standard per lo shopping durante i saldi."}', NULL),
    (386, '(Dialogo) A: "Onko tämä neule alennuksessa?" / B: "Kyllä, se on 50% alennuksella."', 'phrase', '2cd4851baa56cf2f7a35cccfb908c9f5d7b4fa6984d1491847ffcdca020490cb', 'A2', true, 'easy', 'firebase', 2, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "frase_130", "note_culturale": "Dialogo standard per lo shopping durante i saldi."}', NULL),
    (387, '(Dialogo) A: "Is this sweater on sale?" / B: "Yes, it''s 50% off."', 'phrase', '9c6ec635865312c257d825a3ca59dde2d946b3df66cf29ed090da533a0f1c286', 'A2', true, 'easy', 'firebase', 3, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "frase_130", "note_culturale": "Dialogo standard per lo shopping durante i saldi."}', NULL),
    (388, '(Dialogo) A: "Pago io la cena." / B: "No, dai, facciamo alla romana."', 'phrase', '77f322711327b544c8c871ef897dfe35fc5baf73c98a79f5b048bd02eee692aa', 'A2', true, 'easy', 'firebase', 1, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "frase_131", "note_culturale": "Idiomi per ''dividere il conto''. ''Facciamo alla romana'' (IT, dividere in parti uguali), ''jaetaan tasan'' (FI, dividiamo in parti uguali), ''let''s go Dutch'' (EN)."}', NULL),
    (389, '(Dialogo) A: "Minä maksan illallisen." / B: "Ei, jaetaan lasku tasan."', 'phrase', '20bed1f368b9a8ffe826a73819fc75162dcdf0e2f209a95b0b68e785a9fc9e8d', 'A2', true, 'easy', 'firebase', 2, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "frase_131", "note_culturale": "Idiomi per ''dividere il conto''. ''Facciamo alla romana'' (IT, dividere in parti uguali), ''jaetaan tasan'' (FI, dividiamo in parti uguali), ''let''s go Dutch'' (EN)."}', NULL),
    (390, '(Dialogo) A: "I''ll pay for dinner." / B: "No, come on, let''s go Dutch."', 'phrase', '9231c14be6fe32851fc574df3d1202a8725ca3701a48ee8ef3c78a121622aea5', 'A2', true, 'easy', 'firebase', 3, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "frase_131", "note_culturale": "Idiomi per ''dividere il conto''. ''Facciamo alla romana'' (IT, dividere in parti uguali), ''jaetaan tasan'' (FI, dividiamo in parti uguali), ''let''s go Dutch'' (EN)."}', NULL),
    (391, '(Dialogo) A: "Quanto viene?" / B: "Non so, ho perso lo scontrino."', 'phrase', '74728388d183d170fc65791734503a0966e2c4b3aed4614989ac3f76d9e1b184', 'A2', true, 'easy', 'firebase', 1, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "frase_132", "note_culturale": "''Quanto viene?'' è un modo colloquiale A2 per chiedere ''Quanto costa?''."}', NULL),
    (392, '(Dialogo) A: "Paljonko se maksaa?" / B: "En tiedä, kadotin kuitin."', 'phrase', '7823a55fe3ab693e91208abc26ceca392385c05c8a32c61b776709fd465ae68e', 'A2', true, 'easy', 'firebase', 2, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "frase_132", "note_culturale": "''Quanto viene?'' è un modo colloquiale A2 per chiedere ''Quanto costa?''."}', NULL),
    (393, '(Dialogo) A: "How much is it?" / B: "I don''t know, I lost the receipt."', 'phrase', 'df739252e2c969c6f073007b9eba2d410148058b220219bfb7e1ef42bfc096aa', 'A2', true, 'easy', 'firebase', 3, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "frase_132", "note_culturale": "''Quanto viene?'' è un modo colloquiale A2 per chiedere ''Quanto costa?''."}', NULL),
    (394, '(Dialogo) A: "Devo risparmiare un po''." / B: "Sì, dobbiamo tirare la cinghia questo mese."', 'phrase', '33c94ecfaf0261d481c893098b7fd42321fc2bcf80102305855ca96feb482972', 'A2', true, 'easy', 'firebase', 1, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "frase_133", "note_culturale": "Idiomi per ''risparmiare / spendere meno''. Tutte e tre le lingue usano la stessa metafora della cintura: ''tirare la cinghia'' / ''kiristää vyötä'' / ''tighten our belts''."}', NULL),
    (395, '(Dialogo) A: "Minun täytyy säästää vähän." / B: "Kyllä, meidän täytyy kiristää vyötä tässä kuussa."', 'phrase', '78e5f013fbea0c3fe042a0fa8d0f5722e58007b58d9586a59e0448864c91baf1', 'A2', true, 'easy', 'firebase', 2, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "frase_133", "note_culturale": "Idiomi per ''risparmiare / spendere meno''. Tutte e tre le lingue usano la stessa metafora della cintura: ''tirare la cinghia'' / ''kiristää vyötä'' / ''tighten our belts''."}', NULL),
    (396, '(Dialogo) A: "I need to save a bit." / B: "Yeah, we have to tighten our belts this month."', 'phrase', 'a8b685848970a91a385fddd3ea2e59a24185f8e836862d6ef26d30c8e9cc1761', 'A2', true, 'easy', 'firebase', 3, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "frase_133", "note_culturale": "Idiomi per ''risparmiare / spendere meno''. Tutte e tre le lingue usano la stessa metafora della cintura: ''tirare la cinghia'' / ''kiristää vyötä'' / ''tighten our belts''."}', NULL),
    (397, '(Dialogo) A: "Posso avere uno sconto?" / B: "Mi dispiace, i prezzi sono fissi."', 'phrase', '1f85b5b6a5b1054466b4147b57144e4833c56b7c0ebf4875765691702067dc62', 'A2', true, 'easy', 'firebase', 1, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "frase_134", "note_culturale": "Dialogo standard sulla contrattazione (e il suo fallimento)."}', NULL),
    (398, '(Dialogo) A: "Voinko saada alennusta?" / B: "Valitettavasti, hinnat ovat kiinteät."', 'phrase', 'aaa5e26fb04ab6013cd86d92fca54a6696b61740e5365db58a8e932293ebd06a', 'A2', true, 'easy', 'firebase', 2, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "frase_134", "note_culturale": "Dialogo standard sulla contrattazione (e il suo fallimento)."}', NULL),
    (399, '(Dialogo) A: "Can I get a discount?" / B: "I''m sorry, the prices are fixed."', 'phrase', '32e198a61990a5bb8bea835f4723dbd68784e4d7d6a4a13878f2b86f1c7e69dd', 'A2', true, 'easy', 'firebase', 3, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "frase_134", "note_culturale": "Dialogo standard sulla contrattazione (e il suo fallimento)."}', NULL),
    (400, '(Dialogo) A: "Svelti, svelti!" / B: "Accidenti, abbiamo perso il treno!"', 'phrase', '282205f285a36127317c8d1249eadad5df645ed6ccce77db583c6439f6dc3cd5', 'A2', true, 'easy', 'firebase', 1, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "frase_135", "note_culturale": "Reazione a un imprevisto comune in viaggio. ''Perdere il treno'' / ''myöhästyä junasta'' (fare tardi dal treno)."}', NULL),
    (401, '(Dialogo) A: "Nopeasti, nopeasti!" / B: "Voi hitsi, myöhästyimme junasta!"', 'phrase', '7423c4645bd689b635bf2c90d7ad40489eb82d9d38f9b2edf7a3f661b6a76b62', 'A2', true, 'easy', 'firebase', 2, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "frase_135", "note_culturale": "Reazione a un imprevisto comune in viaggio. ''Perdere il treno'' / ''myöhästyä junasta'' (fare tardi dal treno)."}', NULL),
    (402, '(Dialogo) A: "Quick, quick!" / B: "Darn it, we missed the train!"', 'phrase', '10049e7b45c25b09a318605961f5808d3ac35d912d554cfce79eb16c2aa9e820', 'A2', true, 'easy', 'firebase', 3, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "frase_135", "note_culturale": "Reazione a un imprevisto comune in viaggio. ''Perdere il treno'' / ''myöhästyä junasta'' (fare tardi dal treno)."}', NULL),
    (403, '(Dialogo) A: "Scusi, a che ora parte l''aereo per Roma?" / B: "Un attimo... è in ritardo di 20 minuti."', 'phrase', 'f52a2278bb50abffe3301b61cc3064ba0babe77bcd1d739b8b661fb69b340a2a', 'A2', true, 'easy', 'firebase', 1, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "frase_136", "note_culturale": "Chiedere informazioni in aeroporto e ricevere notizia di un ritardo."}', NULL),
    (404, '(Dialogo) A: "Anteeksi, mihin aikaan Rooman-kone lähtee?" / B: "Hetkinen... se on myöhässä 20 minuuttia."', 'phrase', '646a9eb51a90c51581e1b983cb1c70c25655989d7f45152b5a387544a863e1ed', 'A2', true, 'easy', 'firebase', 2, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "frase_136", "note_culturale": "Chiedere informazioni in aeroporto e ricevere notizia di un ritardo."}', NULL),
    (405, '(Dialogo) A: "Excuse me, what time does the plane to Rome leave?" / B: "One moment... it''s delayed by 20 minutes."', 'phrase', 'cbad245a910e047246e7c2dfb9af413e3b6e41a69324273e21825cedd6ed1a29', 'A2', true, 'easy', 'firebase', 3, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "frase_136", "note_culturale": "Chiedere informazioni in aeroporto e ricevere notizia di un ritardo."}', NULL),
    (406, '(Dialogo) A: "Buongiorno, vorrei fare il check-in." / B: "Certo, il passaporto, per favore."', 'phrase', '974f190fc7aed08e99a29f355fd1d33ba494ce56024204dd346856ba0bb30e66', 'A2', true, 'easy', 'firebase', 1, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "frase_137", "note_culturale": "Dialogo standard per il check-in (hotel o aeroporto). ''Fare il check-in'' / ''kirjautua sisään'' (iscriversi dentro)."}', NULL),
    (407, '(Dialogo) A: "Hyvää päivää, haluaisin kirjautua sisään." / B: "Selvä, passi, kiitos."', 'phrase', 'adb38fd5c8ff4fd5049891275b426557e1ccd70d24fb5b2f241790c0dffa9159', 'A2', true, 'easy', 'firebase', 2, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "frase_137", "note_culturale": "Dialogo standard per il check-in (hotel o aeroporto). ''Fare il check-in'' / ''kirjautua sisään'' (iscriversi dentro)."}', NULL),
    (408, '(Dialogo) A: "Good morning, I''d like to check in." / B: "Certainly, your passport, please."', 'phrase', 'fbdb7a8aeb2f255051bb05c6428dea7eddae034b1f64410ed2b7e083da0852d6', 'A2', true, 'easy', 'firebase', 3, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "frase_137", "note_culturale": "Dialogo standard per il check-in (hotel o aeroporto). ''Fare il check-in'' / ''kirjautua sisään'' (iscriversi dentro)."}', NULL),
    (409, '(Dialogo) A: "Dove andate in vacanza?" / B: "Andiamo a fare un giro in Spagna."', 'phrase', 'b68a3189a4734b787c503610f3aa1b3b2f834ea8ed3e78c2974c877ac423f33a', 'A2', true, 'easy', 'firebase', 1, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "frase_138", "note_culturale": "Parlare di piani di viaggio. ''Fare un giro'' (IT) e ''käydä reissulla'' (FI) sono modi colloquiali per ''fare un viaggio''."}', NULL),
    (410, '(Dialogo) A: "Mihin menette lomalle?" / B: "Käydään pienellä reissulla Espanjassa."', 'phrase', '5ac317dd69291000f36126db4dddeb63185a8b452af54717c7f984abc4269ac0', 'A2', true, 'easy', 'firebase', 2, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "frase_138", "note_culturale": "Parlare di piani di viaggio. ''Fare un giro'' (IT) e ''käydä reissulla'' (FI) sono modi colloquiali per ''fare un viaggio''."}', NULL),
    (411, '(Dialogo) A: "Where are you going on holiday?" / B: "We''re going on a trip to Spain."', 'phrase', 'a8ddc7e1e69bc18adff5e31db3908dfbfdfdc537c6ed3ebbb73041089ec858ae', 'A2', true, 'easy', 'firebase', 3, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "frase_138", "note_culturale": "Parlare di piani di viaggio. ''Fare un giro'' (IT) e ''käydä reissulla'' (FI) sono modi colloquiali per ''fare un viaggio''."}', NULL),
    (412, '(Dialogo) A: "Parto per la Finlandia!" / B: "Buon viaggio!"', 'phrase', '91df9e910b186b8b691952b7a571a82c59570a19e647ba9ea3633becf30f1e73', 'A2', true, 'easy', 'firebase', 1, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "frase_139", "note_culturale": "Augurio standard prima di un viaggio."}', NULL),
    (413, '(Dialogo) A: "Lähden Suomeen!" / B: "Hyvää matkaa!"', 'phrase', '0e1f8d8e049c7faac0317a6666bae6649e71d1b734e551cb29191cd33d05ec51', 'A2', true, 'easy', 'firebase', 2, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "frase_139", "note_culturale": "Augurio standard prima di un viaggio."}', NULL),
    (414, '(Dialogo) A: "I''m leaving for Finland!" / B: "Have a good trip!"', 'phrase', '03c658e325b67ad2a68ca425310e3753711447c19254c8780a1d9e5a9a71f036', 'A2', true, 'easy', 'firebase', 3, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "frase_139", "note_culturale": "Augurio standard prima di un viaggio."}', NULL),
    (415, '(Dialogo) A: "Scusi, qual è il binario per Milano?" / B: "È il binario 5."', 'phrase', 'cad4f1ce24cd46ead88d49778b1c13164d22e405f44411777e90c4100fbfd163', 'A2', true, 'easy', 'firebase', 1, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "frase_140", "note_culturale": "Chiedere indicazioni in stazione. ''Binario'' (IT), ''Raide'' (FI), ''Platform'' (EN)."}', NULL),
    (416, '(Dialogo) A: "Anteeksi, miltä raiteelta Milanoon menevä juna lähtee?" / B: "Se on raide 5."', 'phrase', 'bad78abc03a9be296a5829808047f7437b40bbb1f7094b6c72a6c7b5e457905a', 'A2', true, 'easy', 'firebase', 2, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "frase_140", "note_culturale": "Chiedere indicazioni in stazione. ''Binario'' (IT), ''Raide'' (FI), ''Platform'' (EN)."}', NULL),
    (417, '(Dialogo) A: "Excuse me, which platform is for Milan?" / B: "It''s platform 5."', 'phrase', 'f60a306b6a54f4e6405151ed824fd66a937c6bc88b2ec34256213480b2145903', 'A2', true, 'easy', 'firebase', 3, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "frase_140", "note_culturale": "Chiedere indicazioni in stazione. ''Binario'' (IT), ''Raide'' (FI), ''Platform'' (EN)."}', NULL),
    (418, '(Dialogo) A: "Quanto dura il volo?" / B: "Circa tre ore."', 'phrase', 'fb60c526e0bea47172d5801d02203a22e627d9f9bbe742bd0a6d46f63163660b', 'A2', true, 'easy', 'firebase', 1, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "frase_141", "note_culturale": "Domanda e risposta standard sulla durata di un viaggio."}', NULL),
    (419, '(Dialogo) A: "Kauanko lento kestää?" / B: "Noin kolme tuntia."', 'phrase', 'bdcfc23e49637ab4b2bd81c2331ce92b907f1d98bc223e39d7995e7128a7fd49', 'A2', true, 'easy', 'firebase', 2, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "frase_141", "note_culturale": "Domanda e risposta standard sulla durata di un viaggio."}', NULL),
    (420, '(Dialogo) A: "How long is the flight?" / B: "About three hours."', 'phrase', '5db6814ff8584ecfbf7ed5e2a45137447710b2ad2c8057c9ca793dae17737c9b', 'A2', true, 'easy', 'firebase', 3, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "frase_141", "note_culturale": "Domanda e risposta standard sulla durata di un viaggio."}', NULL),
    (421, '(Dialogo) A: "Hai preparato la valigia?" / B: "Non ancora, sono in alto mare!"', 'phrase', 'd2be3317b7d323c9f1347c783ecdb038d24042400f3c11c27f2481b8a319e873', 'A2', true, 'easy', 'firebase', 1, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "frase_142", "note_culturale": "Idiomi per ''non aver ancora finito''. ''Essere in alto mare'' (IT), ''homma on kesken'' (FI, il lavoro è a metà), ''nowhere near done'' (EN)."}', NULL),
    (422, '(Dialogo) A: "Oletko pakannut laukkusi?" / B: "En vielä, homma on ihan kesken!"', 'phrase', '6f3af1114a7af53e929dd6d2d52fe0d91dc948d4ac652595307e7c9913d05d8f', 'A2', true, 'easy', 'firebase', 2, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "frase_142", "note_culturale": "Idiomi per ''non aver ancora finito''. ''Essere in alto mare'' (IT), ''homma on kesken'' (FI, il lavoro è a metà), ''nowhere near done'' (EN)."}', NULL),
    (423, '(Dialogo) A: "Have you packed your suitcase?" / B: "Not yet, I''m nowhere near done!"', 'phrase', '3e0cf7c0a82bd01e0f02fd90a1b542ad3aed0f89a8f4527adc1d656fb61ec60d', 'A2', true, 'easy', 'firebase', 3, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "frase_142", "note_culturale": "Idiomi per ''non aver ancora finito''. ''Essere in alto mare'' (IT), ''homma on kesken'' (FI, il lavoro è a metà), ''nowhere near done'' (EN)."}', NULL),
    (424, '(Dialogo) A: "Devo prendere un taxi per l''aeroporto?" / B: "Sì, è la cosa migliore."', 'phrase', '69713f684924ec19e4f6cb472dab9ecda01e51a8183ae7d5932c02409a933b93', 'A2', true, 'easy', 'firebase', 1, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "frase_143", "note_culturale": "Dare un consiglio. ''È la cosa migliore'' / ''se on paras ratkaisu'' (è la soluzione migliore) / ''that''s your best bet'' (idioma)."}', NULL),
    (425, '(Dialogo) A: "Pitääkö minun ottaa taksi lentokentälle?" / B: "Kyllä, se on paras ratkaisu."', 'phrase', 'f0c6563c979c621b06266b2cbe8b6209be82b800ad3ef07bcf07247331d90fef', 'A2', true, 'easy', 'firebase', 2, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "frase_143", "note_culturale": "Dare un consiglio. ''È la cosa migliore'' / ''se on paras ratkaisu'' (è la soluzione migliore) / ''that''s your best bet'' (idioma)."}', NULL),
    (426, '(Dialogo) A: "Should I take a taxi to the airport?" / B: "Yes, that''s your best bet."', 'phrase', '4673583d27a1d40d51bbe7ce842e5411448040b8a9d078a621f794849cdf629b', 'A2', true, 'easy', 'firebase', 3, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "frase_143", "note_culturale": "Dare un consiglio. ''È la cosa migliore'' / ''se on paras ratkaisu'' (è la soluzione migliore) / ''that''s your best bet'' (idioma)."}', NULL),
    (427, '(Dialogo) A: "A che ora è la colazione in hotel?" / B: "Dalle 7 alle 10."', 'phrase', '82b081e7241f0bb873a5638bfb224d75d4fcb9f3bcbc7fe40a0772817ba88fbf', 'A2', true, 'easy', 'firebase', 1, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "frase_144", "note_culturale": "Richiesta di informazioni standard in hotel."}', NULL),
    (428, '(Dialogo) A: "Mihin aikaan aamiainen on hotellissa?" / B: "Seitsemästä kymmeneen."', 'phrase', '215b4cc80dc93e3ea8ca17fc99967b4b8af6875c99b15c9f3852905427cbd5db', 'A2', true, 'easy', 'firebase', 2, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "frase_144", "note_culturale": "Richiesta di informazioni standard in hotel."}', NULL),
    (429, '(Dialogo) A: "What time is breakfast at the hotel?" / B: "From 7 to 10."', 'phrase', '9f1117cc126593afce3e361ad7c0ee8823e8fda43612c1321299b7bd5f949542', 'A2', true, 'easy', 'firebase', 3, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "frase_144", "note_culturale": "Richiesta di informazioni standard in hotel."}', NULL),
    (430, '(Dialogo) A: "Scusi, è questo l''autobus per il centro?" / B: "No, deve prendere il 10."', 'phrase', '3120f15ac3aa8c93b928790f6ac586c8fea73b430290a1731469e0cfdb8a5e3b', 'A2', true, 'easy', 'firebase', 1, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "frase_145", "note_culturale": "Chiedere e correggere indicazioni per i trasporti pubblici."}', NULL),
