    (1077, 'Vanhempani ovat synnyttäneet minut, mutta eivät ymmärrä minua.', 'phrase', '226656db222e4bdaa1568a9767bc70ad02246cc3be65dd9563cf97e402e6d201', 'B1', false, 'medium', 'firebase', 2, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "phr_famiglia_012", "note_culturale": null}', NULL),
    (1078, 'My parents brought me into the world, but they don''t understand me.', 'phrase', 'f3b4f2b9d19d48553f5f96e00f9d0a50550d17de378dcd26485df82c705d1853', 'B1', false, 'medium', 'firebase', 3, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "phr_famiglia_012", "note_culturale": null}', NULL),
    (1079, 'Devo andare a trovare i miei nonni, è da tanto che non li vedo.', 'phrase', '1d8a0cdf54950bb1a87b4628d3cb1dc29763bd5217eb5c1b4769019bfb141e80', 'A2', false, 'easy', 'firebase', 1, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "phr_famiglia_013", "note_culturale": null}', NULL),
    (1080, 'Minun täytyy mennä tapaamaan isovanhempiani, on pitkä aika siitä kun olen nähnyt heitä.', 'phrase', '0ca7003ba489c24d8feaf92a2124993b2c9c4a608342e1736fb7133e30a6030c', 'A2', false, 'easy', 'firebase', 2, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "phr_famiglia_013", "note_culturale": null}', NULL),
    (1081, 'I have to go visit my grandparents, it''s been a long time since I''ve seen them.', 'phrase', '173a75a9d5433b8db07b722bd745f37681c606ca0c146741465ae0e8e8b45cc8', 'A2', false, 'easy', 'firebase', 3, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "phr_famiglia_013", "note_culturale": null}', NULL),
    (1082, 'Siamo cresciuti insieme, siamo come fratelli.', 'phrase', 'a341709ca72c2e8b1674d1186027c1ca08805b68e5ae1c11b20c3c19e33989f6', 'A1', false, 'easy', 'firebase', 1, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "phr_famiglia_014", "note_culturale": null}', NULL),
    (1083, 'Olemme kasvaneet yhdessä, olemme kuin veljiä.', 'phrase', 'e985c964eb3e45bf79250877799c999f85be283953aa75d98a8677832f0a58c7', 'A1', false, 'easy', 'firebase', 2, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "phr_famiglia_014", "note_culturale": null}', NULL),
    (1084, 'We grew up together, we are like brothers.', 'phrase', '6bebd7a5ecb9781e1e36a5948358b67e127fdad1079420a063a8f245c6dfc42d', 'A1', false, 'easy', 'firebase', 3, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "phr_famiglia_014", "note_culturale": null}', NULL),
    (1085, 'Mia moglie è la mia roccia.', 'phrase', 'cceb1e3e5f8565d83e30da5ead95f426a49e88d1cdbf239ccd150074cb339a48', 'B1', true, 'medium', 'firebase', 1, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "phr_famiglia_015", "note_culturale": "Metafora per indicare una persona di grande supporto."}', NULL),
    (1086, 'Vaimoni on minun kallioni.', 'phrase', 'c06bb9d69bceea1f95e80879f8a005ab9b37cdb07282aa3d7bfa54bc9ee9e2ca', 'B1', true, 'medium', 'firebase', 2, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "phr_famiglia_015", "note_culturale": "Metafora per indicare una persona di grande supporto."}', NULL),
    (1087, 'My wife is my rock.', 'phrase', '78b3b231d1f9105f70c2cd93504607c1ae392a802afdcc6586ef17d1a8ae660e', 'B1', true, 'medium', 'firebase', 3, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "phr_famiglia_015", "note_culturale": "Metafora per indicare una persona di grande supporto."}', NULL),
    (1088, 'Non mi parlare di mio padre, per favore.', 'phrase', '1ef89e31761177a851431a61585ec08e6c0a1dc0f07cb46c2e3ae8b37bb3b7b5', 'B1', false, 'medium', 'firebase', 1, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "phr_famiglia_016", "note_culturale": null}', NULL),
    (1089, 'Älä puhu minulle isästäni, kiitos.', 'phrase', '1f7aedd9886a490c17a222b82b1c7e1fa0c54a3f020f5ccb1fc6f19e5186da3a', 'B1', false, 'medium', 'firebase', 2, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "phr_famiglia_016", "note_culturale": null}', NULL),
    (1090, 'Don''t talk to me about my father, please.', 'phrase', '83d9d55253dbaa9426ee90b4bf1dfe4bc1c9761ced440e24286a7eaab106d0aa', 'B1', false, 'medium', 'firebase', 3, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "phr_famiglia_016", "note_culturale": null}', NULL),
    (1091, 'I miei figli sono la mia priorità.', 'phrase', '7cfcea2a508667a4115c5bb7452daf12cba46417fcdd2b81369fbe46367d749a', 'A2', false, 'easy', 'firebase', 1, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "phr_famiglia_017", "note_culturale": null}', NULL),
    (1092, 'Lapseni ovat minun prioriteettini.', 'phrase', '8a2b56f242670ecade94b2f406f2889eabac217ca48446e9d20bcf18e6838d9c', 'A2', false, 'easy', 'firebase', 2, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "phr_famiglia_017", "note_culturale": null}', NULL),
    (1093, 'My children are my priority.', 'phrase', '58c0a8c591c855b064bdee9d422e5df84e163027988907909257c333603b0a06', 'A2', false, 'easy', 'firebase', 3, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "phr_famiglia_017", "note_culturale": null}', NULL),
    (1094, 'Siamo una coppia di fatto.', 'phrase', '738413072f8bd74a152e0df61b18b03e1d6e606b281ae8f968dd8207d6398d75', 'A2', false, 'easy', 'firebase', 1, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "phr_famiglia_018", "note_culturale": "Descrive una coppia non sposata ma che convive."}', NULL),
    (1095, 'Olemme avopari.', 'phrase', '3ba13308969299bf1a9973d2dea03842b0cfa902163e87edcfc87d3e99ed4e94', 'A2', false, 'easy', 'firebase', 2, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "phr_famiglia_018", "note_culturale": "Descrive una coppia non sposata ma che convive."}', NULL),
    (1096, 'We are a common-law couple.', 'phrase', '363ef5645c1a162f84d0469b579ce228c7c92813b495a98e8c056dde26a127a0', 'A2', false, 'easy', 'firebase', 3, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "phr_famiglia_018", "note_culturale": "Descrive una coppia non sposata ma che convive."}', NULL),
    (1097, 'Ho tagliato i ponti con mio fratello.', 'phrase', '2eee25f9fc1927a492699250ab449ae770c7b553182b383d8c3c5f8ae11be648', 'B1', true, 'medium', 'firebase', 1, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "phr_famiglia_019", "note_culturale": "Significa interrompere definitivamente una relazione."}', NULL),
    (1098, 'Olen katkaissut välit veljeeni.', 'phrase', '2da50bc677d655fcf6d6bddf216cf2f3ad9fa4dd5e2544ab97cfa1564261ee0f', 'B1', true, 'medium', 'firebase', 2, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "phr_famiglia_019", "note_culturale": "Significa interrompere definitivamente una relazione."}', NULL),
    (1099, 'I''ve cut ties with my brother.', 'phrase', '6b147765f3e8462d265e9669c8d0674e5dec4a63fba2d6d2e86187f314ff0dc0', 'B1', true, 'medium', 'firebase', 3, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "phr_famiglia_019", "note_culturale": "Significa interrompere definitivamente una relazione."}', NULL),
