    (1101, 'Perhe on pyhä!', 'phrase', 'dd803c6d30eda670bc1b8556a8bf6a2f5d12c919b6bb627d4ee1b42e573e1474', 'A2', false, 'easy', 'firebase', 2, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "phr_famiglia_020", "note_culturale": null}', NULL),
    (1102, 'Family is sacred!', 'phrase', 'e17ad09af07e9fa18b8b19ccebf5b93704f3a21269fec87a5a16b7ebbe6062fc', 'A2', false, 'easy', 'firebase', 3, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "phr_famiglia_020", "note_culturale": null}', NULL),
    (1103, 'Non mi sono mai sentito a casa con la mia famiglia.', 'phrase', '4405ffb70e9e1a65865cd413c5495546a1ad1748205ad458d585b42a8d290975', 'B1', false, 'medium', 'firebase', 1, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "phr_famiglia_021", "note_culturale": null}', NULL),
    (1104, 'En ole koskaan tuntenut oloani kotoisaksi perheeni kanssa.', 'phrase', '081aad8117c5d07fc972192766abc2ce97bb624b7150191c1657d00650cb30fe', 'B1', false, 'medium', 'firebase', 2, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "phr_famiglia_021", "note_culturale": null}', NULL),
    (1105, 'I''ve never felt at home with my family.', 'phrase', '5b70d6e8ceb00399881a9314a39ff95259f60ac62a800662bfbd6f7bcee5bfbf', 'B1', false, 'medium', 'firebase', 3, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "phr_famiglia_021", "note_culturale": null}', NULL),
    (1106, 'Mi fai venire il latte alle ginocchia!', 'phrase', 'ec21deec8dec1e24b2e395168ad1d7e0e9cecb153c3d7f3db3501064ea8f4aca', 'B2', true, 'hard', 'firebase', 1, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "phr_famiglia_022", "note_culturale": "Modo di dire molto colorito per esprimere grande irritazione."}', NULL),
    (1107, 'Saat minut tulemaan maitoa polviini!', 'phrase', '361b84bb46d1825608764fcb050ca4a1f25019213a996e390c1f4a5badaba527', 'B2', true, 'hard', 'firebase', 2, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "phr_famiglia_022", "note_culturale": "Modo di dire molto colorito per esprimere grande irritazione."}', NULL),
    (1108, 'You make my milk come to my knees!', 'phrase', '35ce45fc9669cf5108fe1892b1aa43ea2e21430dba1e5fc276124a6e14dc2cb2', 'B2', true, 'hard', 'firebase', 3, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "phr_famiglia_022", "note_culturale": "Modo di dire molto colorito per esprimere grande irritazione."}', NULL),
    (1109, 'È tutta farina del suo sacco.', 'phrase', '9a28bcbfc9ec710d6ba4e4a498db0177d924954aeb4296a3dafe2f157d0593a6', 'B1', true, 'medium', 'firebase', 1, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "phr_famiglia_023", "note_culturale": "Significa che il successo è dovuto solo ai suoi sforzi."}', NULL),
    (1110, 'Se on kaikki hänen omaa ansiotaan.', 'phrase', 'e23022bb9cc78ed0e705d83f4ef250a7418eca34b028f5c1ab90def73b22d23b', 'B1', true, 'medium', 'firebase', 2, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "phr_famiglia_023", "note_culturale": "Significa che il successo è dovuto solo ai suoi sforzi."}', NULL),
    (1111, 'It''s all his own doing.', 'phrase', '05d939df38e6ccd71789081fb4fcda0f48e5e0316777232f029cfe71dec770cd', 'B1', true, 'medium', 'firebase', 3, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "phr_famiglia_023", "note_culturale": "Significa che il successo è dovuto solo ai suoi sforzi."}', NULL),
    (1112, 'Avere un tetto sulla testa è già tanto.', 'phrase', 'c076c7bfccfa69bd5f815e7a7582a52233e8054977a844d848fda5fe94e64982', 'A2', true, 'easy', 'firebase', 1, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "phr_famiglia_024", "note_culturale": "Apprezzare le cose essenziali della vita."}', NULL),
    (1113, 'Katto pään päällä on jo paljon.', 'phrase', 'eb0a31f95fac035d8175d00a4216eda51812e91ec54f9f628d311f391ba3fcf6', 'A2', true, 'easy', 'firebase', 2, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "phr_famiglia_024", "note_culturale": "Apprezzare le cose essenziali della vita."}', NULL),
    (1114, 'Having a roof over your head is already a lot.', 'phrase', '64b02cd9b03f6c2703005d6f862b6eb1797d211ce1dd40212fd7d68e719c6e4b', 'A2', true, 'easy', 'firebase', 3, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "phr_famiglia_024", "note_culturale": "Apprezzare le cose essenziali della vita."}', NULL),
