    (1116, 'Olemme yhtenäinen perhe, myötä- ja vastoinkäymisissä.', 'phrase', '200ec6137e2350b103e64bb6b0172f596424d66666072be85f6b51b41959afbc', 'A2', false, 'easy', 'firebase', 2, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "phr_famiglia_025", "note_culturale": null}', NULL),
