    (1124, 'Non sopporto più il mio coinquilino!', 'phrase', 'c8820677d34013e34ffa9a131a88dfaca2b7b8077dee29d35a85f3caf86a57c9', 'A2', false, 'easy', 'firebase', 1, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "phr_famiglia_028", "note_culturale": null}', NULL),
