    (1134, 'Olemme asuneet yhdessä viisi vuotta, mutta emme ole vielä naimisissa.', 'phrase', 'ed857d4e479f2168a8c31d4bd731995e69ba8576715713c99e821918872657c6', 'B1', false, 'medium', 'firebase', 2, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "phr_famiglia_031", "note_culturale": null}', NULL),
