    (1137, 'Veljeni on perheen musta lammas.', 'phrase', '5e8dd2ddfcd406b5e33a5eccb0bdbc22cf423ef192464e62188b92c5bd7af627', 'B2', true, 'hard', 'firebase', 2, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "phr_famiglia_032", "note_culturale": "Espressione usata per descrivere una persona che si distingue negativamente dalla famiglia."}', NULL),
    (1138, 'My brother is the black sheep of the family.', 'phrase', 'f4de9649d3c667c1ef713a3cfc8c0111aaa926b17f1b7c68b453c4d6b7a39e5a', 'B2', true, 'hard', 'firebase', 3, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "phr_famiglia_032", "note_culturale": "Espressione usata per descrivere una persona che si distingue negativamente dalla famiglia."}', NULL),
    (1139, 'Non mi parlare di mia suocera!', 'phrase', '94564f0d94b5f126182728cf93c48ccc4df3643227c6ca78e9fe849110f6fe2f', 'A2', false, 'easy', 'firebase', 1, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "phr_famiglia_033", "note_culturale": null}', NULL),
    (1140, 'Älä puhu minulle anopistani!', 'phrase', '5e9222c17affd279d78ed68a9fa09c40a27d6ee252a18524dc507685ad494207', 'A2', false, 'easy', 'firebase', 2, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "phr_famiglia_033", "note_culturale": null}', NULL),
