    (1144, 'I argued with my partner... again!', 'phrase', 'd2e50f2f36bff8f48cd8f02684f9d43dc5b479835e0dc33d3c101ffa74301132', 'A2', false, 'easy', 'firebase', 3, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "phr_famiglia_034", "note_culturale": null}', NULL),
    (1145, 'I miei nipoti sono la mia gioia più grande.', 'phrase', 'c600bc7906a7328060eb7f6145488550495ec7c5ce41efad54ed01fa1a72a955', 'A2', false, 'easy', 'firebase', 1, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "phr_famiglia_035", "note_culturale": null}', NULL),
    (1146, 'Lapsenlapseni ovat suurin iloni.', 'phrase', 'b45738ca466bf45a0618bb4b209d2d29cab09e4eb3cf09946e7fd131fc4e1555', 'A2', false, 'easy', 'firebase', 2, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "phr_famiglia_035", "note_culturale": null}', NULL),
