    (1154, 'La mia ragazza e io stiamo pensando di andare a convivere.', 'phrase', '2649b5ce84476fa4c413b49abc202132142da9724fd88014819c980fd22f77bf', 'B1', false, 'medium', 'firebase', 1, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "phr_famiglia_038", "note_culturale": null}', NULL),
    (1155, 'Tyttöystäväni ja minä harkitsemme yhteen muuttamista.', 'phrase', '61090ea4be66ecf2087ce9588038c176bd9663fe7821fe347ce77af03c971700', 'B1', false, 'medium', 'firebase', 2, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "phr_famiglia_038", "note_culturale": null}', NULL),
    (1156, 'My girlfriend and I are thinking about moving in together.', 'phrase', '80e107fe4580804d3604a996b686a3bd345ab7e87b46d3acf167a5dda1432f82', 'B1', false, 'medium', 'firebase', 3, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "phr_famiglia_038", "note_culturale": null}', NULL),
    (1157, 'Non ho più l''età per queste cose, sono un padre di famiglia!', 'phrase', 'a2294730ee6c64e8ecfb01f27d8c140d05592e1416dae04de20c69fca61c0ba5', 'B1', false, 'medium', 'firebase', 1, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "phr_famiglia_039", "note_culturale": null}', NULL),
    (1158, 'Olen liian vanha näihin juttuihin, olen perheenisä!', 'phrase', '57f67cf1bd9afbcd6ea066118493ed4d435fd9754c7ed4c1bf8898cd25f5d6e8', 'B1', false, 'medium', 'firebase', 2, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "phr_famiglia_039", "note_culturale": null}', NULL),
