    (1161, 'Äitini laittaa aina kapuloita rattaisiin!', 'phrase', '803b60cac480be6eef193e010ef28314a46e8689abbd2c8cdec2fe4bfbcf9408', 'B2', true, 'hard', 'firebase', 2, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "phr_famiglia_040", "note_culturale": "Espressione usata per descrivere qualcuno che ostacola i tuoi piani."}', NULL),
